BEGIN;

-- ************************************************************
-- 1. BIOLOGÍA (2º, 3º, 4º ESO) — 30 historias
-- ************************************************************

INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES

-- 2º ESO: ecosistemas y nutrición
('biologia', 'eso', '{2}', '["Un ecosistema está formado por un medio físico y los seres vivos que lo habitan","Los factores abióticos como la luz y la temperatura condicionan la vida en ese medio","Los organismos productores captan la energía solar y fabrican materia orgánica","Los consumidores obtienen la energía alimentándose de otros seres vivos","Los descomponedores reciclan la materia orgánica y cierran el ciclo de nutrientes"]'),
('biologia', 'eso', '{2}', '["La nutrición autótrofa permite a las plantas fabricar su propio alimento","Absorben agua y sales minerales del suelo a través de las raíces","La savia bruta asciende por el tallo hasta las hojas de la planta","En las hojas se realiza la fotosíntesis combinando la savia bruta con el dióxido de carbono","La savia elaborada resultante se distribuye por toda la planta para alimentarla"]'),
('biologia', 'eso', '{2}', '["Los ecosistemas acuáticos se clasifican en marinos y de agua dulce","Los marinos incluyen océanos, mares y arrecifes de coral","Los de agua dulce comprenden ríos, lagos y humedales","La salinidad del agua es un factor clave que determina las especies presentes","La contaminación del agua amenaza la biodiversidad de estos ecosistemas"]'),
('biologia', 'eso', '{2}', '["La nutrición heterótrofa consiste en obtener alimento a partir de otros seres vivos","Los herbívoros se alimentan directamente de plantas y algas","Los carnívoros obtienen su energía cazando y consumiendo a otros animales","Los omnívoros combinan ambas fuentes de alimento en su dieta","Los descomponedores se alimentan de materia orgánica muerta o en descomposición"]'),
('biologia', 'eso', '{2}', '["El bioma de la selva tropical se caracteriza por temperaturas altas y lluvias abundantes","Alberga la mayor biodiversidad del planeta en todos sus estratos","El bioma del desierto presenta escasas precipitaciones y temperaturas extremas","La tundra se encuentra en zonas polares con suelos permanentemente helados","Cada bioma refleja la adaptación de los seres vivos a las condiciones climáticas"]'),
('biologia', 'eso', '{2}', '["Los nutrientes que necesitamos se dividen en macronutrientes y micronutrientes","Los hidratos de carbono son la principal fuente de energía rápida del organismo","Las proteínas son esenciales para construir y reparar los tejidos del cuerpo","Las grasas almacenan energía de reserva y protegen los órganos internos","Las vitaminas y minerales regulan procesos metabólicos y son imprescindibles en pequeñas cantidades"]'),
('biologia', 'eso', '{2}', '["Las relaciones intraespecíficas se dan entre individuos de la misma especie","La competencia intraespecífica se produce cuando compiten por alimento o territorio","Las relaciones interespecíficas se dan entre individuos de especies diferentes","El parasitismo beneficia a una especie mientras perjudica a la otra","El mutualismo es una relación donde ambas especies se benefician mutuamente"]'),
('biologia', 'eso', '{2}', '["El aparato digestivo transforma los alimentos en nutrientes asimilables","La digestión mecánica comienza en la boca con la masticación de los alimentos","La digestión química actúa mediante enzimas que descomponen las moléculas complejas","En el intestino delgado se absorben la mayoría de los nutrientes hacia la sangre","El intestino grueso absorbe el agua restante y forma las heces para su expulsión"]'),
('biologia', 'eso', '{2}', '["La sucesión ecológica es el proceso de cambio gradual en un ecosistema","Las especies pioneras colonizan primero un terreno desnudo o alterado","Estas modifican el medio y permiten la llegada de nuevas especies","La comunidad se va haciendo más compleja y diversa con el tiempo","Finalmente se alcanza la comunidad clímax, que es estable y madura"]'),
('biologia', 'eso', '{2}', '["El aparato respiratorio se encarga del intercambio de gases con el exterior","El aire entra por las fosas nasales donde se filtra, calienta y humedece","Desciende por la tráquea y los bronquios hasta llegar a los pulmones","En los alvéolos pulmonares se produce el intercambio de oxígeno y dióxido de carbono","El oxígeno pasa a la sangre y el dióxido de carbono se expulsa al exterior"]'),

-- 3º ESO: aparatos y genética
('biologia', 'eso', '{3}', '["El aparato excretor elimina las sustancias de desecho producidas por el metabolismo","Los riñones filtran la sangre y producen la orina con los productos de desecho","La orina desciende por los uréteres hasta la vejiga urinaria","La vejiga almacena la orina hasta que se expulsa al exterior por la uretra","Los pulmones y la piel también participan en la eliminación de sustancias de desecho"]'),
('biologia', 'eso', '{3}', '["El ADN contiene la información genética de un organismo","Está formado por dos cadenas enrolladas en una estructura de doble hélice","Cada cadena está compuesta por nucleótidos con cuatro bases nitrogenadas diferentes","Las bases se emparejan siguiendo una regla fija: adenina con timina y guanina con citosina","Esta secuencia de bases codifica las instrucciones para fabricar las proteínas"]'),
('biologia', 'eso', '{3}', '["El sistema nervioso central está formado por el encéfalo y la médula espinal","El cerebro es el órgano principal que controla las funciones superiores","El cerebelo coordina los movimientos y mantiene el equilibrio corporal","La médula espinal transmite los impulsos nerviosos entre el cerebro y el cuerpo","El sistema nervioso periférico conecta el sistema central con los órganos y tejidos"]'),
('biologia', 'eso', '{3}', '["Los genes son fragmentos de ADN que contienen la información para un carácter","Cada individuo hereda dos copias de cada gen, una del padre y otra de la madre","Los alelos son las diferentes versiones que puede tener un mismo gen","Un alelo dominante se manifiesta siempre que está presente en el genotipo","Un alelo recesivo solo se manifiesta cuando las dos copias son iguales"]'),
('biologia', 'eso', '{3}', '["El aparato locomotor está formado por el sistema esquelético y el sistema muscular","Los huesos forman el esqueleto que sostiene y protege los órganos internos","Las articulaciones son las uniones entre huesos que permiten el movimiento","Los músculos esqueléticos se contraen para producir el movimiento de los huesos","Los tendones unen los músculos a los huesos y los ligamentos unen los huesos entre sí"]'),
('biologia', 'eso', '{3}', '["La meiosis es un tipo de división celular que produce células sexuales o gametos","La célula madre diploide contiene dos juegos completos de cromosomas","En la primera división meiótica se separan los cromosomas homólogos","En la segunda división se separan las cromátidas hermanas de cada cromosoma","Al final se obtienen cuatro células haploides con la mitad de cromosomas"]'),
('biologia', 'eso', '{3}', '["El sistema endocrino regula el organismo mediante la producción de hormonas","Las hormonas son mensajeros químicos que viajan por la sangre hasta sus órganos diana","La hipófisis es considerada la glándula maestra porque controla a otras glándulas","El tiroides regula el metabolismo basal mediante las hormonas tiroideas","El páncreas produce insulina que regula los niveles de glucosa en la sangre"]'),
('biologia', 'eso', '{3}', '["Las leyes de Mendel establecen los principios básicos de la herencia genética","La primera ley indica que al cruzar dos líneas puras toda la descendencia es uniforme","La segunda ley señala que los caracteres se separan al formarse los gametos","La tercera ley establece que los caracteres diferentes se heredan de forma independiente","Mendel descubrió estos principios experimentando con plantas de guisante en el siglo XIX"]'),
('biologia', 'eso', '{3}', '["El aparato reproductor masculino produce los espermatozoides en los testículos","Estos maduran y se almacenan en el epidídimo hasta la eyaculación","El aparato reproductor femenino produce los óvulos en los ovarios","La fecundación se produce cuando un espermatozoide se une a un óvulo","El embrión se implanta en el útero donde se desarrolla durante nueve meses"]'),
('biologia', 'eso', '{3}', '["Los receptores sensoriales captan los estímulos del medio ambiente","Los fotorreceptores del ojo detectan la luz y permiten la visión","Los mecanorreceptores del oído captan las ondas sonoras y el equilibrio","Los quimiorreceptores de la nariz y la lengua detectan olores y sabores","La información sensorial viaja por los nervios hasta el cerebro para ser procesada"]'),

-- 4º ESO: evolución y ecología
('biologia', 'eso', '{4}', '["Lamarck propuso que los organismos se adaptan mediante el uso y desuso de sus órganos","Darwin formuló la teoría de la selección natural tras su viaje en el Beagle","Observó que los individuos con características ventajosas sobreviven mejor","Estos transmiten esas características a su descendencia a lo largo del tiempo","La selección natural es el mecanismo principal de la evolución biológica"]'),
('biologia', 'eso', '{4}', '["El efecto invernadero es un fenómeno natural que mantiene la temperatura de la Tierra","Los gases de efecto invernadero atrapan parte del calor que emite la superficie terrestre","La actividad humana ha aumentado la concentración de estos gases en la atmósfera","Este incremento provoca un calentamiento global con consecuencias en el clima","El deshielo polar y la subida del nivel del mar son efectos directos de este problema"]'),
('biologia', 'eso', '{4}', '["Las mutaciones son cambios aleatorios en la secuencia del ADN de un organismo","Pueden ser causadas por errores durante la replicación del material genético","También pueden ser provocadas por agentes externos como la radiación ultravioleta","Algunas mutaciones son perjudiciales, otras neutras y unas pocas resultan beneficiosas","Las mutaciones beneficiosas proporcionan la variabilidad genética que impulsa la evolución"]'),
('biologia', 'eso', '{4}', '["La biodiversidad es la variedad de formas de vida que existen en nuestro planeta","Incluye la diversidad genética, la diversidad de especies y la diversidad de ecosistemas","Las regiones tropicales concentran la mayor biodiversidad del mundo","La destrucción de hábitats es la principal causa de la pérdida de biodiversidad actual","Conservar la biodiversidad es esencial para mantener el equilibrio de los ecosistemas"]'),
('biologia', 'eso', '{4}', '["La tectónica de placas explica el movimiento de las grandes placas de la litosfera","Las placas se desplazan sobre la astenosfera impulsadas por corrientes de convección","Cuando dos placas chocan pueden formarse cordilleras o producirse terremotos","Cuando se separan surge nueva corteza oceánica a partir del magma del manto","La distribución de volcanes y terremotos coincide con los bordes de las placas"]'),
('biologia', 'eso', '{4}', '["Los fósiles son restos o huellas de organismos que vivieron en el pasado","Se forman cuando los restos quedan enterrados y se mineralizan a lo largo del tiempo","Los paleontólogos estudian los fósiles para reconstruir la historia de la vida","La datación radiométrica permite conocer la edad de los fósiles más antiguos","El registro fósil muestra una progresión desde formas simples a formas más complejas"]'),
('biologia', 'eso', '{4}', '["La ingeniería genética permite modificar el ADN de los organismos de forma artificial","Se pueden aislar genes de interés y transferirlos a otro organismo distinto","Los organismos transgénicos contienen genes de una especie diferente en su genoma","Esta tecnología tiene aplicaciones en la medicina, la agricultura y la industria","Plantea debates éticos sobre los límites de la manipulación de la vida"]'),
('biologia', 'eso', '{4}', '["El desarrollo sostenible busca satisfacer las necesidades actuales sin comprometer las futuras","Se basa en tres pilares: el económico, el social y el medioambiental","La sobreexplotación de los recursos naturales pone en peligro el equilibrio del planeta","Las energías renovables son una alternativa limpia a los combustibles fósiles","Reducir, reutilizar y reciclar son acciones individuales clave para la sostenibilidad"]'),
('biologia', 'eso', '{4}', '["La evolución humana comenzó hace millones de años en el continente africano","Los primeros homínidos eran bípedos pero aún tenían un cerebro pequeño","El Homo habilis fue el primero en fabricar herramientas de piedra","El Homo erectus aprendió a controlar el fuego y se expandió fuera de África","El Homo sapiens apareció hace unos trescientos mil años con un cerebro muy desarrollado"]'),
('biologia', 'eso', '{4}', '["La lluvia ácida se produce cuando los gases contaminantes reaccionan con el agua atmosférica","Los óxidos de azufre y nitrógeno de las fábricas y vehículos son los principales causantes","Estos compuestos forman ácido sulfúrico y ácido nítrico que caen con las precipitaciones","La lluvia ácida daña los bosques, acidifica los lagos y deteriora los edificios","Reducir las emisiones industriales y del transporte es fundamental para combatirla"]');

-- ************************************************************
-- 2. EDUCACIÓN FÍSICA (2º, 3º, 4º ESO) — 30 historias
-- ************************************************************

INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES

-- 2º ESO: deportes colectivos
('ed-fisica', 'eso', '{2}', '["El voleibol se juega entre dos equipos de seis jugadores separados por una red","El objetivo es pasar el balón por encima de la red y que toque el suelo del campo contrario","Cada equipo dispone de un máximo de tres toques para devolver el balón","Los jugadores rotan sus posiciones en el campo cada vez que recuperan el saque","Un set se gana al alcanzar veinticinco puntos con dos de ventaja"]'),
('ed-fisica', 'eso', '{2}', '["El balonmano es un deporte de equipo que se juega con las manos","Cada equipo tiene siete jugadores en el campo incluyendo al portero","El objetivo es lanzar el balón a la portería contraria para marcar goles","Los jugadores de campo no pueden retener el balón más de tres segundos","Solo el portero puede entrar en el área de portería para defender"]'),
('ed-fisica', 'eso', '{2}', '["El hockey es un deporte de equipo que se puede jugar sobre hierba o hielo","Los jugadores utilizan un stick o palo para golpear y conducir la bola","El objetivo es marcar goles introduciendo la bola en la portería contraria","El trabajo en equipo y la coordinación entre los jugadores son fundamentales","Las reglas prohíben levantar el stick por encima de la cintura por seguridad"]'),
('ed-fisica', 'eso', '{2}', '["La cooperación es un principio fundamental en los deportes de equipo","Cada jugador cumple una función específica dentro del sistema táctico del equipo","La comunicación entre compañeros facilita el desarrollo de las jugadas de ataque","En defensa es importante la ayuda mutua y la cobertura de las posiciones","El juego limpio y el respeto al adversario son valores esenciales del deporte"]'),
('ed-fisica', 'eso', '{2}', '["El fútbol sala se juega entre dos equipos de cinco jugadores incluido el portero","El campo es más pequeño que el de fútbol y está cubierto por un suelo duro","Las sustituciones son ilimitadas y se pueden hacer en cualquier momento del partido","El balón es más pequeño y pesado que el de fútbol para facilitar el control","Los partidos se dividen en dos partes de veinte minutos a reloj parado"]'),
('ed-fisica', 'eso', '{2}', '["El rugby se juega entre dos equipos de quince jugadores en un campo rectangular","El objetivo es apoyar el balón ovalado en la zona de marca del equipo contrario","Los jugadores pueden correr con el balón y pasarlo hacia atrás a un compañero","Los placajes son la forma de detener al portador del balón","El ensayo vale cinco puntos y la conversión posterior vale dos puntos más"]'),
('ed-fisica', 'eso', '{2}', '["El ultimate frisbee es un deporte de equipo que se juega con un disco volador","No hay árbitro y los propios jugadores resuelven las disputas con espíritu deportivo","No se puede correr con el disco en la mano, solo se puede pasar","Se marca un punto cuando un compañero recibe el disco en la zona de gol contraria","Es un deporte que fomenta especialmente el juego limpio y la autorregulación"]'),
('ed-fisica', 'eso', '{2}', '["Los principios tácticos ofensivos buscan crear situaciones de ventaja frente al rival","Mantener la posesión del balón es la base para construir ataques eficaces","La amplitud en ataque abre espacios y dificulta la defensa del equipo contrario","La profundidad permite progresar rápidamente hacia la portería rival","Los cambios de ritmo sorprenden al adversario y generan oportunidades de gol"]'),
('ed-fisica', 'eso', '{2}', '["Los principios tácticos defensivos buscan recuperar el balón y evitar goles","El repliegue consiste en retroceder rápidamente para organizar la defensa","La presión al portador del balón dificulta que el rival progrese con comodidad","Las coberturas y permutas aseguran que ningún espacio quede desprotegido","La anticipación permite interceptar pases y recuperar la posesión antes del ataque"]'),
('ed-fisica', 'eso', '{2}', '["El bádminton es un deporte de raqueta que se juega con un volante de plumas","Se puede jugar en modalidad de individuales o de dobles sobre una pista dividida por red","El volante no puede tocar el suelo ya que el punto se pierde automáticamente","Los golpes básicos incluyen el clear, el drop, el drive y el smash","La agilidad y los reflejos rápidos son habilidades clave en este deporte"]'),

-- 3º ESO: planificación del entrenamiento
('ed-fisica', 'eso', '{3}', '["La frecuencia cardíaca es un indicador fundamental para controlar la intensidad del ejercicio","Se mide contando las pulsaciones por minuto en la muñeca o el cuello","La frecuencia cardíaca máxima teórica se estima restando la edad a doscientos veinte","La zona de trabajo aeróbico se sitúa entre el sesenta y el ochenta por ciento del máximo","Trabajar en la zona adecuada maximiza los beneficios del entrenamiento cardiovascular"]'),
('ed-fisica', 'eso', '{3}', '["La resistencia aeróbica es la capacidad de realizar esfuerzos prolongados de intensidad moderada","Se mejora con actividades continuas como correr, nadar o montar en bicicleta","La resistencia anaeróbica permite esfuerzos intensos pero de corta duración","Los sprints y los ejercicios de alta intensidad desarrollan la capacidad anaeróbica","Un buen plan de entrenamiento combina ambos tipos de resistencia de forma equilibrada"]'),
('ed-fisica', 'eso', '{3}', '["La fuerza muscular es la capacidad de vencer o mantener una resistencia externa","La fuerza máxima es la mayor tensión que un músculo puede generar en una contracción","La fuerza explosiva combina velocidad y fuerza en un movimiento rápido como un salto","La fuerza resistencia permite mantener contracciones repetidas durante un tiempo prolongado","El entrenamiento con cargas progresivas es el método más eficaz para desarrollar la fuerza"]'),
('ed-fisica', 'eso', '{3}', '["Un plan de entrenamiento debe seguir los principios del entrenamiento deportivo","El principio de progresión indica que la carga debe aumentar de forma gradual","El principio de especificidad señala que el entrenamiento debe ser adaptado al objetivo","El principio de recuperación establece que el descanso es necesario para mejorar","El principio de individualización recuerda que cada persona responde de forma diferente"]'),
('ed-fisica', 'eso', '{3}', '["La velocidad es la capacidad de realizar un movimiento en el menor tiempo posible","La velocidad de reacción es el tiempo que tardamos en responder a un estímulo","La velocidad de desplazamiento determina lo rápido que nos movemos de un punto a otro","La velocidad gestual se refiere a la rapidez con la que ejecutamos un gesto técnico","Se mejora con ejercicios de corta duración y máxima intensidad con descansos completos"]'),
('ed-fisica', 'eso', '{3}', '["La periodización del entrenamiento organiza la temporada en fases con objetivos específicos","El periodo preparatorio general desarrolla la base física con trabajo variado de condición","El periodo preparatorio específico se centra en las cualidades más importantes del deporte","El periodo competitivo mantiene la forma y busca el máximo rendimiento en las pruebas","El periodo de transición permite la recuperación física y mental del deportista"]'),
('ed-fisica', 'eso', '{3}', '["La flexibilidad es la capacidad de las articulaciones para alcanzar su máxima amplitud de movimiento","Los estiramientos estáticos consisten en mantener una posición durante varios segundos","Los estiramientos dinámicos implican movimientos controlados que aumentan progresivamente el rango","Una buena flexibilidad previene lesiones y mejora la eficacia de los gestos deportivos","Se recomienda estirar después del calentamiento o al finalizar la actividad física"]'),
('ed-fisica', 'eso', '{3}', '["El método continuo de entrenamiento consiste en un esfuerzo prolongado sin pausas","Es ideal para mejorar la resistencia aeróbica y la eficiencia cardiovascular","El método interválico alterna periodos de trabajo intenso con periodos de recuperación","El método de repeticiones utiliza esfuerzos máximos con descansos largos y completos","La combinación de estos métodos permite un entrenamiento completo y variado"]'),
('ed-fisica', 'eso', '{3}', '["El calentamiento específico prepara los músculos y articulaciones que más se van a usar","Debe incluir movimientos similares a los de la actividad principal que se va a realizar","Aumenta la temperatura muscular y mejora la elasticidad de los tejidos","Activa el sistema nervioso para mejorar la coordinación y el tiempo de reacción","Un buen calentamiento reduce significativamente el riesgo de sufrir lesiones"]'),
('ed-fisica', 'eso', '{3}', '["La vuelta a la calma es la fase final de toda sesión de entrenamiento","Consiste en reducir progresivamente la intensidad del ejercicio","Ayuda al organismo a volver a su estado de reposo de forma gradual","Incluye ejercicios suaves como caminar y estiramientos de los músculos trabajados","Favorece la eliminación de sustancias de desecho acumuladas durante el esfuerzo"]'),

-- 4º ESO: salud y primeros auxilios
('ed-fisica', 'eso', '{4}', '["La conducta PAS es el protocolo básico de actuación ante un accidente","La P significa Proteger el lugar para evitar nuevos peligros o accidentes","La A significa Alertar llamando al teléfono de emergencias 112 con calma","La S significa Socorrer atendiendo a la víctima sin moverla innecesariamente","Seguir este orden garantiza la seguridad del socorrista y una atención eficaz"]'),
('ed-fisica', 'eso', '{4}', '["La reanimación cardiopulmonar es una técnica de emergencia para salvar vidas","Se aplica cuando una persona no respira y no tiene pulso detectable","Se comienza con treinta compresiones torácicas en el centro del pecho","Después se realizan dos insuflaciones de aire boca a boca si se está formado","Se continúa alternando compresiones e insuflaciones hasta que llegue la ayuda sanitaria"]'),
('ed-fisica', 'eso', '{4}', '["El sedentarismo es la falta de actividad física regular y es un problema de salud pública","Aumenta el riesgo de enfermedades cardiovasculares, diabetes y obesidad","La Organización Mundial de la Salud recomienda al menos sesenta minutos diarios de actividad","El ejercicio regular fortalece el corazón, los huesos y mejora el estado de ánimo","Incorporar hábitos activos como caminar o subir escaleras es un primer paso importante"]'),
('ed-fisica', 'eso', '{4}', '["Las lesiones deportivas más comunes afectan a músculos, tendones y ligamentos","Un esguince es una distensión o rotura parcial de los ligamentos de una articulación","Una contractura es una contracción involuntaria y persistente de un músculo","La tendinitis es la inflamación de un tendón por sobreuso o esfuerzo repetitivo","La prevención mediante calentamiento, técnica correcta y descanso es la mejor estrategia"]'),
('ed-fisica', 'eso', '{4}', '["La posición lateral de seguridad se usa cuando una persona está inconsciente pero respira","Se coloca a la víctima de lado para evitar que se atragante con su propia lengua","Se flexiona la pierna superior para mantener la estabilidad de la postura","El brazo inferior se coloca extendido para evitar que ruede boca abajo","Se debe vigilar la respiración de la persona hasta que lleguen los servicios de emergencia"]'),
('ed-fisica', 'eso', '{4}', '["La composición corporal describe la proporción de grasa, músculo y hueso del cuerpo","El índice de masa corporal relaciona el peso con la altura para valorar el estado nutricional","Un porcentaje excesivo de grasa corporal puede indicar sobrepeso u obesidad","La actividad física regular ayuda a mantener una composición corporal saludable","Una alimentación equilibrada combinada con ejercicio es la clave para el bienestar"]'),
('ed-fisica', 'eso', '{4}', '["El vendaje funcional se utiliza para inmovilizar parcialmente una articulación lesionada","Se aplica con tiras de esparadrapo o venda adhesiva sobre la zona afectada","Permite cierta movilidad pero limita los movimientos que podrían agravar la lesión","Es una técnica muy utilizada en el deporte para facilitar la recuperación activa","Debe ser colocado por una persona con conocimientos para no causar problemas circulatorios"]'),
('ed-fisica', 'eso', '{4}', '["El método RICE se aplica como tratamiento inmediato en lesiones agudas de tejidos blandos","La R significa reposo para evitar el agravamiento de la lesión","La I significa aplicar hielo durante quince o veinte minutos para reducir la inflamación","La C significa compresión con un vendaje elástico para limitar la hinchazón","La E significa elevación de la extremidad afectada por encima del nivel del corazón"]'),
('ed-fisica', 'eso', '{4}', '["El dopaje es el uso de sustancias prohibidas para mejorar el rendimiento deportivo","Atenta contra la salud del deportista y contra los valores del juego limpio","Los controles antidopaje se realizan mediante análisis de orina y sangre","La Agencia Mundial Antidopaje actualiza cada año la lista de sustancias prohibidas","Los deportistas que dan positivo se enfrentan a sanciones y a la pérdida de sus títulos"]'),
('ed-fisica', 'eso', '{4}', '["Los beneficios psicológicos del ejercicio físico son tan importantes como los físicos","La actividad física libera endorfinas que producen una sensación de bienestar","Reduce los niveles de estrés, ansiedad y mejora la calidad del sueño","Aumenta la autoestima y la confianza en las propias capacidades personales","Practicar deporte en grupo fomenta las habilidades sociales y el sentimiento de pertenencia"]');

-- ************************************************************
-- 3. FÍSICA (2º, 3º, 4º ESO) — 30 historias
-- ************************************************************

INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES

-- 2º ESO: fuerza y movimiento
('fisica', 'eso', '{2}', '["La velocidad es una magnitud que indica la distancia recorrida en un tiempo determinado","Se calcula dividiendo el espacio recorrido entre el tiempo empleado","La unidad de velocidad en el Sistema Internacional es el metro por segundo","Un movimiento rectilíneo uniforme tiene velocidad constante en línea recta","En la vida cotidiana también usamos kilómetros por hora como unidad de velocidad"]'),
('fisica', 'eso', '{2}', '["Una fuerza es toda acción capaz de modificar el estado de movimiento de un cuerpo","Las fuerzas se miden en newtons con un instrumento llamado dinamómetro","Si la fuerza resultante sobre un objeto es cero el objeto mantiene su estado de reposo","Si la fuerza resultante es diferente de cero el objeto acelera en esa dirección","La ley de Newton establece que la aceleración es proporcional a la fuerza aplicada"]'),
('fisica', 'eso', '{2}', '["La fuerza de rozamiento se opone al movimiento de un cuerpo sobre una superficie","Depende de la naturaleza de las superficies en contacto y de la fuerza normal","Sin rozamiento un objeto en movimiento seguiría moviéndose indefinidamente","El rozamiento es necesario para poder caminar y para que los coches frenen","Los lubricantes como el aceite reducen el rozamiento entre las piezas de una máquina"]'),
('fisica', 'eso', '{2}', '["La presión es la fuerza ejercida por unidad de superficie y se mide en pascales","Un mismo peso ejerce más presión si se reparte en una superficie menor","Por eso los clavos tienen la punta afilada para concentrar la fuerza","La presión atmosférica es la fuerza que ejerce el aire sobre la superficie terrestre","A mayor altitud la presión atmosférica disminuye porque hay menos aire encima"]'),
('fisica', 'eso', '{2}', '["El principio de Arquímedes explica por qué algunos objetos flotan en el agua","Todo cuerpo sumergido recibe un empuje vertical hacia arriba igual al peso del fluido desalojado","Si el empuje es mayor que el peso del objeto este flota en la superficie","Si el peso es mayor que el empuje el objeto se hunde hasta el fondo","Los barcos flotan porque desplazan un volumen de agua cuyo peso supera al del barco"]'),
('fisica', 'eso', '{2}', '["La aceleración mide cómo cambia la velocidad de un cuerpo a lo largo del tiempo","Se calcula dividiendo el cambio de velocidad entre el tiempo transcurrido","La unidad de aceleración en el Sistema Internacional es el metro por segundo al cuadrado","Un movimiento rectilíneo uniformemente acelerado tiene aceleración constante","La aceleración de la gravedad en la Tierra es de aproximadamente nueve coma ocho metros por segundo al cuadrado"]'),
('fisica', 'eso', '{2}', '["Las máquinas simples facilitan la realización de un trabajo con menos esfuerzo","La palanca es una barra rígida que gira alrededor de un punto de apoyo llamado fulcro","La polea permite cambiar la dirección de una fuerza tirando de una cuerda","El plano inclinado reduce la fuerza necesaria para elevar un objeto a cierta altura","Todas las máquinas simples aplican el principio de conservación de la energía"]'),
('fisica', 'eso', '{2}', '["La caída libre es el movimiento de un cuerpo que solo está sometido a la gravedad","Todos los cuerpos caen con la misma aceleración independientemente de su masa","Galileo demostró este principio dejando caer objetos desde la torre de Pisa","En el vacío una pluma y una bola de acero caen exactamente a la misma velocidad","La resistencia del aire es la que hace que en la práctica los objetos caigan a distinta velocidad"]'),
('fisica', 'eso', '{2}', '["La ley de Hooke describe el comportamiento de los materiales elásticos como los muelles","La fuerza necesaria para deformar un muelle es proporcional a su estiramiento","La constante de elasticidad del muelle determina su rigidez o resistencia a deformarse","Si se supera el límite elástico el material se deforma de forma permanente","Esta ley tiene aplicaciones en balanzas, suspensiones de vehículos y amortiguadores"]'),
('fisica', 'eso', '{2}', '["La tercera ley de Newton establece que toda acción tiene una reacción igual y opuesta","Cuando empujas una pared la pared te empuja a ti con la misma fuerza","Un cohete se propulsa porque los gases expulsados hacia abajo lo empujan hacia arriba","Estas fuerzas de acción y reacción actúan siempre sobre cuerpos diferentes","Es la ley que explica cómo funcionan los motores a reacción y la propulsión"]'),

-- 3º ESO: energía y ondas
('fisica', 'eso', '{3}', '["La energía cinética es la que posee un cuerpo por estar en movimiento","Depende de la masa del cuerpo y del cuadrado de su velocidad","La energía potencial gravitatoria depende de la masa, la gravedad y la altura","El principio de conservación establece que la energía total se mantiene constante","La energía se transforma de unas formas a otras pero nunca se crea ni se destruye"]'),
('fisica', 'eso', '{3}', '["Una onda es una perturbación que se propaga transportando energía sin transportar materia","Las ondas mecánicas necesitan un medio material para propagarse como el sonido","Las ondas electromagnéticas pueden viajar por el vacío como la luz","La longitud de onda es la distancia entre dos crestas consecutivas de la onda","La frecuencia indica cuántas oscilaciones se producen en un segundo y se mide en hercios"]'),
('fisica', 'eso', '{3}', '["El sonido es una onda mecánica que se propaga por la vibración de las partículas del medio","La velocidad del sonido en el aire es de aproximadamente trescientos cuarenta metros por segundo","El tono de un sonido depende de su frecuencia: a mayor frecuencia más agudo es","La intensidad del sonido se mide en decibelios y depende de la amplitud de la onda","El eco se produce cuando las ondas sonoras rebotan en una superficie y regresan"]'),
('fisica', 'eso', '{3}', '["El trabajo mecánico se realiza cuando una fuerza desplaza un cuerpo en su dirección","Se calcula multiplicando la fuerza por la distancia recorrida en la dirección de la fuerza","La potencia es la rapidez con la que se realiza un trabajo y se mide en vatios","Una máquina más potente realiza el mismo trabajo en menos tiempo","La unidad de trabajo y energía en el Sistema Internacional es el julio"]'),
('fisica', 'eso', '{3}', '["La luz es una onda electromagnética que se propaga a trescientos mil kilómetros por segundo","La reflexión ocurre cuando la luz rebota al chocar con una superficie como un espejo","La refracción se produce cuando la luz cambia de dirección al pasar de un medio a otro","La dispersión de la luz blanca a través de un prisma produce los colores del arcoíris","Las lentes convergentes concentran los rayos de luz y las divergentes los separan"]'),
('fisica', 'eso', '{3}', '["El calor se transmite por tres mecanismos diferentes: conducción, convección y radiación","La conducción transfiere calor entre sólidos en contacto directo sin movimiento de materia","La convección transfiere calor en fluidos mediante corrientes de materia caliente que asciende","La radiación transmite calor mediante ondas electromagnéticas sin necesitar medio material","El sol calienta la Tierra por radiación ya que las ondas viajan por el vacío del espacio"]'),
('fisica', 'eso', '{3}', '["Las fuentes de energía renovables se regeneran de forma natural y son inagotables","La energía solar aprovecha la radiación del sol mediante paneles fotovoltaicos o térmicos","La energía eólica utiliza la fuerza del viento para mover aerogeneradores","La energía hidráulica aprovecha la caída del agua embalsada para generar electricidad","Estas fuentes no producen gases de efecto invernadero durante su funcionamiento"]'),
('fisica', 'eso', '{3}', '["La energía nuclear se obtiene a partir de las reacciones que ocurren en los núcleos atómicos","La fisión nuclear consiste en dividir un núcleo pesado en dos núcleos más ligeros","Este proceso libera una enorme cantidad de energía que se usa en las centrales nucleares","La fusión nuclear une núcleos ligeros como los de hidrógeno para formar helio","La fusión es el proceso que ocurre en el interior del sol y produce su energía"]'),
('fisica', 'eso', '{3}', '["La eficiencia energética mide cuánta energía útil se obtiene de la energía total consumida","Ninguna máquina real tiene una eficiencia del cien por cien debido a las pérdidas","La mayor parte de la energía perdida se disipa en forma de calor por el rozamiento","Las bombillas LED son mucho más eficientes que las antiguas bombillas incandescentes","Mejorar la eficiencia energética reduce el consumo de recursos y la contaminación"]'),
('fisica', 'eso', '{3}', '["El espectro electromagnético abarca todas las ondas electromagnéticas ordenadas por su frecuencia","Las ondas de radio tienen la frecuencia más baja y se usan en las telecomunicaciones","La luz visible es solo una pequeña parte del espectro que nuestros ojos pueden detectar","Los rayos ultravioleta tienen más energía que la luz visible y pueden dañar la piel","Los rayos X y gamma son los de mayor energía y se usan en medicina e industria"]'),

-- 4º ESO: electricidad y átomos
('fisica', 'eso', '{4}', '["La corriente eléctrica es el flujo ordenado de cargas eléctricas a través de un conductor","La intensidad de corriente mide la cantidad de carga que circula por segundo","La diferencia de potencial o voltaje es la fuerza que impulsa las cargas por el circuito","La resistencia eléctrica se opone al paso de la corriente y se mide en ohmios","La ley de Ohm establece que el voltaje es igual a la intensidad por la resistencia"]'),
('fisica', 'eso', '{4}', '["El modelo atómico ha evolucionado a lo largo de la historia de la ciencia","Dalton propuso que los átomos eran esferas macizas e indivisibles","Thomson descubrió el electrón y propuso un modelo de masa positiva con electrones incrustados","Rutherford demostró que el átomo tiene un núcleo pequeño y denso con carga positiva","Bohr introdujo la idea de que los electrones giran en órbitas con niveles de energía definidos"]'),
('fisica', 'eso', '{4}', '["Un circuito eléctrico en serie conecta todos los componentes uno tras otro en una sola línea","Si un elemento del circuito en serie se abre toda la corriente deja de circular","En un circuito en paralelo cada componente tiene su propio camino independiente","Si un elemento del circuito en paralelo falla los demás siguen funcionando","Las instalaciones domésticas usan circuitos en paralelo para que cada aparato sea independiente"]'),
('fisica', 'eso', '{4}', '["La tabla periódica organiza los elementos químicos según su número atómico creciente","Los elementos del mismo grupo tienen propiedades químicas similares","Los metales se sitúan a la izquierda y los no metales a la derecha de la tabla","Los gases nobles ocupan el último grupo y son muy poco reactivos","Dmitri Mendeléyev fue el primero en proponer una tabla periódica con huecos para elementos desconocidos"]'),
('fisica', 'eso', '{4}', '["Los imanes generan un campo magnético que ejerce fuerzas sobre otros imanes y materiales ferromagnéticos","Todo imán tiene dos polos: el norte y el sur que no se pueden separar","Los polos iguales se repelen y los polos diferentes se atraen mutuamente","La Tierra se comporta como un gran imán con un campo magnético que nos protege","La brújula funciona porque su aguja imantada se orienta con el campo magnético terrestre"]'),
('fisica', 'eso', '{4}', '["La potencia eléctrica indica la rapidez con que un aparato consume energía eléctrica","Se mide en vatios y se calcula multiplicando el voltaje por la intensidad de corriente","Un kilovatio hora es la energía consumida por un aparato de mil vatios durante una hora","La factura eléctrica se calcula según los kilovatios hora consumidos cada mes","Los electrodomésticos con etiqueta A consumen menos energía que los de etiqueta inferior"]'),
('fisica', 'eso', '{4}', '["Los enlaces químicos unen los átomos para formar moléculas o compuestos estables","El enlace iónico se forma cuando un átomo cede electrones a otro formando iones","El enlace covalente se produce cuando dos átomos comparten electrones entre ellos","El enlace metálico une los átomos de un metal compartiendo una nube de electrones","El tipo de enlace determina las propiedades físicas del compuesto como su punto de fusión"]'),
('fisica', 'eso', '{4}', '["La radiactividad es la emisión espontánea de partículas o radiación desde núcleos inestables","Fue descubierta por Henri Becquerel y estudiada en profundidad por Marie Curie","La radiación alfa está formada por núcleos de helio y tiene poco poder de penetración","La radiación beta consiste en electrones y penetra más que la radiación alfa","La radiación gamma es una onda electromagnética de alta energía con gran poder de penetración"]'),
('fisica', 'eso', '{4}', '["La energía eléctrica se genera en las centrales eléctricas mediante diferentes fuentes","En las centrales térmicas se queman combustibles fósiles para calentar agua y producir vapor","El vapor hace girar una turbina conectada a un generador que produce electricidad","La electricidad se transporta por líneas de alta tensión hasta los puntos de consumo","Los transformadores reducen el voltaje para que sea seguro en los hogares y comercios"]'),
('fisica', 'eso', '{4}', '["Las reacciones químicas implican la reorganización de los átomos para formar nuevas sustancias","Los reactivos son las sustancias iniciales y los productos son las sustancias resultantes","La ley de conservación de la masa establece que nada se crea ni se destruye","Por eso las ecuaciones químicas deben ajustarse igualando los átomos de cada elemento","La velocidad de una reacción depende de factores como la temperatura y la concentración"]');

-- ************************************************************
-- 4. HISTORIA (2º, 3º, 4º ESO) — 30 historias
-- ************************************************************

INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES

-- 2º ESO: Edad Media y Al-Ándalus
('historia', 'eso', '{2}', '["La caída del Imperio Romano de Occidente en el 476 marca el inicio de la Edad Media","Los pueblos germánicos crearon nuevos reinos en los antiguos territorios del imperio","El feudalismo se convirtió en el sistema político y social dominante en Europa","Los señores feudales ofrecían protección a los campesinos a cambio de trabajo y lealtad","La Iglesia católica fue la institución más poderosa y unificadora durante este periodo"]'),
('historia', 'eso', '{2}', '["En el año 711 los musulmanes cruzaron el estrecho de Gibraltar y entraron en la Península","Derrotaron al rey visigodo don Rodrigo en la batalla de Guadalete","En pocos años conquistaron casi toda la Península Ibérica","Córdoba se convirtió en la capital de Al-Ándalus y un centro cultural brillante","La convivencia entre musulmanes, cristianos y judíos generó un rico intercambio cultural"]'),
('historia', 'eso', '{2}', '["La Reconquista fue el proceso de recuperación de los territorios peninsulares por los reinos cristianos","Comenzó en Covadonga en el año 722 con la victoria de don Pelayo sobre los musulmanes","El avance cristiano fue lento durante los primeros siglos por la fortaleza del califato","La batalla de las Navas de Tolosa en 1212 marcó un punto de inflexión decisivo","Los Reyes Católicos completaron la Reconquista con la toma de Granada en 1492"]'),
('historia', 'eso', '{2}', '["El Califato de Córdoba alcanzó su máximo esplendor en el siglo X con Abderramán III","La ciudad de Córdoba llegó a ser una de las más grandes y cultas de Europa","Su mezquita es una obra maestra de la arquitectura islámica que aún se conserva","Científicos y filósofos como Averroes difundieron el saber clásico griego por Europa","La fitna o guerra civil provocó la desintegración del califato en reinos de taifas en 1031"]'),
('historia', 'eso', '{2}', '["Las Cruzadas fueron expediciones militares organizadas por el Papa para recuperar Tierra Santa","La primera Cruzada partió en 1096 y logró conquistar Jerusalén tres años después","Se establecieron estados cruzados en Oriente Próximo que duraron casi dos siglos","Las Cruzadas facilitaron el contacto comercial y cultural entre Europa y Oriente","A pesar de los conflictos se produjo un intercambio de conocimientos y productos"]'),
('historia', 'eso', '{2}', '["La sociedad feudal estaba organizada en tres estamentos: nobleza, clero y campesinos","La nobleza guerrera poseía las tierras y ofrecía protección militar a sus vasallos","El clero se dedicaba a la oración y controlaba la cultura y la educación","Los campesinos trabajaban la tierra del señor y le entregaban parte de la cosecha","La movilidad social era prácticamente inexistente y se nacía en un estamento de por vida"]'),
('historia', 'eso', '{2}', '["El arte románico se desarrolló en Europa entre los siglos XI y XII","Sus iglesias se caracterizan por muros gruesos, arcos de medio punto y escasa iluminación","La escultura románica tenía una función didáctica para enseñar la fe a los fieles","El arte gótico surgió en Francia en el siglo XII como una evolución del románico","Las catedrales góticas destacan por sus altos arcos apuntados y grandes vidrieras de colores"]'),
('historia', 'eso', '{2}', '["El Camino de Santiago se convirtió en la principal ruta de peregrinación de la Europa medieval","Miles de peregrinos recorrían el camino para venerar las reliquias del apóstol Santiago","A lo largo de la ruta surgieron hospitales, monasterios y pueblos para atender a los viajeros","El Camino facilitó el intercambio cultural y artístico entre los pueblos europeos","Todavía hoy miles de personas recorren el Camino de Santiago cada año"]'),
('historia', 'eso', '{2}', '["La peste negra llegó a Europa en 1347 y causó la muerte de un tercio de la población","La enfermedad se transmitía a través de las pulgas de las ratas en los barcos comerciales","Las ciudades fueron las más afectadas por la falta de higiene y la densidad de población","La catástrofe demográfica provocó una grave crisis económica y social","La escasez de mano de obra campesina desencadenó revueltas sociales por toda Europa"]'),
('historia', 'eso', '{2}', '["Los reinos de taifas surgieron tras la fragmentación del Califato de Córdoba en 1031","Eran pequeños estados independientes que competían entre sí por el poder y el territorio","Su debilidad militar les obligó a pagar tributos a los reinos cristianos del norte","A pesar de su fragilidad política vivieron un periodo de gran esplendor cultural","Los almorávides y almohades vinieron del norte de África para unificar Al-Ándalus"]'),

-- 3º ESO: Edad Moderna
('historia', 'eso', '{3}', '["El Renacimiento fue un movimiento cultural que surgió en Italia en el siglo XV","Se inspiró en la cultura clásica de Grecia y Roma y puso al ser humano en el centro","Artistas como Leonardo da Vinci y Miguel Ángel crearon obras maestras del arte universal","La invención de la imprenta por Gutenberg en 1440 revolucionó la difusión del conocimiento","El espíritu humanista se extendió por toda Europa transformando la ciencia y la cultura"]'),
('historia', 'eso', '{3}', '["Cristóbal Colón llegó a América el 12 de octubre de 1492 financiado por los Reyes Católicos","Buscaba una nueva ruta hacia las Indias navegando hacia el oeste por el océano Atlántico","Este descubrimiento abrió una era de exploración y conquista del continente americano","Hernán Cortés conquistó el imperio azteca y Francisco Pizarro sometió al imperio inca","España se convirtió en la mayor potencia mundial gracias a los recursos del Nuevo Mundo"]'),
('historia', 'eso', '{3}', '["La Reforma protestante fue iniciada por Martín Lutero en Alemania en 1517","Lutero criticó la venta de indulgencias y clavó sus noventa y cinco tesis en Wittenberg","Sus ideas se difundieron rápidamente gracias a la imprenta por toda Europa","La Iglesia católica respondió con la Contrarreforma y el Concilio de Trento","Las guerras de religión enfrentaron a católicos y protestantes durante más de un siglo"]'),
('historia', 'eso', '{3}', '["El absolutismo fue un sistema político donde el rey concentraba todo el poder del Estado","Luis XIV de Francia fue el máximo representante del absolutismo con su corte en Versalles","El monarca gobernaba sin contar con parlamentos ni asambleas representativas","El derecho divino justificaba que el poder del rey provenía directamente de Dios","La Ilustración cuestionó el absolutismo y defendió la razón y los derechos individuales"]'),
('historia', 'eso', '{3}', '["La Ilustración fue un movimiento intelectual del siglo XVIII basado en la razón y el progreso","Filósofos como Voltaire, Montesquieu y Rousseau criticaron los abusos del poder absoluto","Montesquieu propuso la separación de poderes en ejecutivo, legislativo y judicial","Rousseau defendió la soberanía popular y el contrato social entre gobernantes y gobernados","Las ideas ilustradas inspiraron revoluciones como la francesa y la independencia americana"]'),
('historia', 'eso', '{3}', '["El imperio español en América organizó los territorios en virreinatos y capitanías generales","El virreinato de Nueva España abarcaba México y gran parte de Centroamérica","El virreinato del Perú comprendía gran parte de Sudamérica","La explotación de las minas de plata de Potosí financió a la corona española durante siglos","La mezcla de culturas indígena, europea y africana creó una nueva identidad americana"]'),
('historia', 'eso', '{3}', '["La revolución científica del siglo XVII transformó la forma de entender el mundo","Copérnico propuso el modelo heliocéntrico con el Sol en el centro del sistema","Galileo confirmó este modelo con sus observaciones telescópicas de los planetas","Newton formuló la ley de gravitación universal que explicaba el movimiento de los astros","El método científico basado en la observación y la experimentación se consolidó como forma de conocimiento"]'),
('historia', 'eso', '{3}', '["El Barroco fue el estilo artístico dominante en Europa durante el siglo XVII","Se caracterizó por la exageración, el dramatismo y el juego de luces y sombras","En pintura destacaron artistas como Caravaggio, Rubens y Velázquez","La arquitectura barroca empleaba formas curvas y una decoración exuberante","En España el Siglo de Oro combinó el Barroco con una producción literaria excepcional"]'),
('historia', 'eso', '{3}', '["La Guerra de los Treinta Años enfrentó a potencias europeas entre 1618 y 1648","Comenzó como un conflicto religioso entre católicos y protestantes en el Sacro Imperio","Francia intervino apoyando a los protestantes para debilitar a los Habsburgo","La Paz de Westfalia en 1648 puso fin al conflicto y redefinió las fronteras europeas","España salió muy debilitada del conflicto perdiendo su hegemonía en Europa"]'),
('historia', 'eso', '{3}', '["La independencia de los Estados Unidos se proclamó el 4 de julio de 1776","Las trece colonias británicas se rebelaron contra los impuestos sin representación parlamentaria","George Washington lideró el ejército continental contra las tropas británicas","Francia apoyó militarmente a los colonos contribuyendo a la victoria final","La Constitución de 1787 estableció una república federal y un sistema de separación de poderes"]'),

-- 4º ESO: Contemporánea y guerras mundiales
('historia', 'eso', '{4}', '["La Revolución Francesa estalló en 1789 con la toma de la Bastilla por el pueblo de París","La Asamblea Nacional abolió los privilegios feudales y aprobó la Declaración de Derechos","El periodo del Terror de Robespierre llevó a miles de personas a la guillotina","Napoleón Bonaparte dio un golpe de Estado en 1799 y se proclamó emperador en 1804","Las guerras napoleónicas extendieron las ideas revolucionarias por toda Europa"]'),
('historia', 'eso', '{4}', '["La Revolución Industrial comenzó en Gran Bretaña a finales del siglo XVIII","La máquina de vapor de James Watt transformó la producción industrial","Las fábricas sustituyeron a los talleres artesanales y atrajeron población del campo","Se construyeron ferrocarriles que conectaron ciudades y facilitaron el comercio","Las duras condiciones laborales de los obreros dieron origen al movimiento obrero"]'),
('historia', 'eso', '{4}', '["La Primera Guerra Mundial estalló en 1914 tras el asesinato del archiduque Francisco Fernando","Las alianzas dividieron a Europa en dos bloques enfrentados: la Triple Entente y los Imperios Centrales","La guerra de trincheras convirtió el conflicto en una larga y sangrienta guerra de desgaste","La entrada de Estados Unidos en 1917 desequilibró la balanza a favor de los aliados","El armisticio de noviembre de 1918 puso fin a una guerra que causó millones de víctimas"]'),
('historia', 'eso', '{4}', '["La crisis de 1929 provocó el hundimiento de la bolsa de Wall Street en Estados Unidos","El desempleo masivo y la miseria se extendieron rápidamente por todo el mundo","La crisis económica favoreció el auge de los totalitarismos en Europa","Hitler llegó al poder en Alemania en 1933 con el partido nacionalsocialista","Mussolini ya había instaurado el fascismo en Italia desde 1922 como modelo autoritario"]'),
('historia', 'eso', '{4}', '["La Segunda Guerra Mundial comenzó en 1939 con la invasión alemana de Polonia","La Alemania nazi ocupó gran parte de Europa occidental en una rápida ofensiva","La invasión de la Unión Soviética en 1941 abrió un nuevo y decisivo frente de guerra","El desembarco de Normandía en junio de 1944 inició la liberación de Europa occidental","La guerra terminó en 1945 con la rendición de Alemania y el lanzamiento de bombas atómicas sobre Japón"]'),
('historia', 'eso', '{4}', '["La Guerra Fría enfrentó a Estados Unidos y la Unión Soviética tras la Segunda Guerra Mundial","El mundo se dividió en dos bloques: el capitalista occidental y el comunista oriental","La crisis de los misiles de Cuba en 1962 llevó al mundo al borde de una guerra nuclear","La carrera espacial y la carrera armamentística fueron expresiones de esta rivalidad","La caída del muro de Berlín en 1989 simbolizó el fin de la Guerra Fría"]'),
('historia', 'eso', '{4}', '["El Holocausto fue el genocidio sistemático de seis millones de judíos por la Alemania nazi","Los nazis promovieron una ideología racista que consideraba a los judíos seres inferiores","Los judíos fueron recluidos en guetos y después deportados a campos de concentración","Campos como Auschwitz se convirtieron en centros de exterminio masivo e industrial","Tras la guerra los juicios de Núremberg juzgaron a los responsables por crímenes contra la humanidad"]'),
('historia', 'eso', '{4}', '["La descolonización de África y Asia se aceleró después de la Segunda Guerra Mundial","La India logró su independencia del Reino Unido en 1947 liderada por Mahatma Gandhi","En África los movimientos independentistas se multiplicaron durante las décadas de 1950 y 1960","Muchos nuevos estados enfrentaron graves problemas de inestabilidad política y pobreza","Las antiguas potencias coloniales mantuvieron su influencia económica sobre los nuevos países"]'),
('historia', 'eso', '{4}', '["La Unión Europea tiene su origen en la Comunidad Europea del Carbón y del Acero de 1951","El Tratado de Roma de 1957 creó la Comunidad Económica Europea con seis países fundadores","El Acta Única Europea de 1986 avanzó hacia un mercado único sin fronteras interiores","El Tratado de Maastricht de 1992 estableció la Unión Europea y sentó las bases del euro","España ingresó en la Comunidad Económica Europea en 1986 tras su transición democrática"]'),
('historia', 'eso', '{4}', '["La transición española a la democracia comenzó tras la muerte de Franco en 1975","El rey Juan Carlos I impulsó la reforma política nombrando a Adolfo Suárez presidente","Se legalizaron los partidos políticos y se celebraron elecciones democráticas en 1977","La Constitución de 1978 fue aprobada por referéndum y estableció una monarquía parlamentaria","El intento de golpe de Estado del 23 de febrero de 1981 fracasó y fortaleció la democracia"]');

-- ************************************************************
-- 5. INGLÉS (2º, 3º, 4º ESO) — 30 historias (EN INGLÉS)
-- ************************************************************

INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES

-- 2º ESO: past tense stories
('ingles', 'eso', '{2}', '["Last weekend, my family decided to go on a trip to the countryside","We woke up early on Saturday morning and packed our bags quickly","We drove for about two hours until we reached a beautiful village","We spent the day hiking through the mountains and taking photographs","We were exhausted but very happy when we finally arrived home"]'),
('ingles', 'eso', '{2}', '["When I was ten years old, I moved to a new city with my parents","At first, I was very nervous because I did not know anybody there","On my first day at school, a girl called Ana talked to me and was very kind","She introduced me to her group of friends during the break","By the end of the month, I felt at home and had many new friends"]'),
('ingles', 'eso', '{2}', '["The detective arrived at the old mansion on a dark and rainy night","He found a broken window and muddy footprints on the floor inside","He followed the footprints to the library where a painting had disappeared","He noticed a small piece of fabric caught on the window frame","The next day, he identified the thief thanks to that important clue"]'),
('ingles', 'eso', '{2}', '["Maria wanted to learn how to cook her grandmother''s famous paella","First, her grandmother showed her how to prepare all the ingredients carefully","Then, she heated the olive oil in a large pan and added the vegetables","After that, she poured in the rice and the special broth with saffron","Finally, they enjoyed the most delicious paella Maria had ever tasted"]'),
('ingles', 'eso', '{2}', '["The school organised a talent show for all the students last Friday","Many students signed up to sing, dance, play instruments or perform magic tricks","My friend Carlos practised a guitar song for two weeks before the show","When he played on the stage, the audience clapped and cheered enthusiastically","He won the first prize and felt very proud of his hard work"]'),
('ingles', 'eso', '{2}', '["It was a sunny afternoon and we decided to go to the swimming pool","We changed into our swimming costumes and put on plenty of sunscreen","I jumped into the deep end while my friend preferred to enter slowly","We played water polo and had races to see who could swim the fastest","After a couple of hours, we were tired and went home for a nice cold drink"]'),
('ingles', 'eso', '{2}', '["My grandfather told me an interesting story about his childhood last night","He grew up in a small village where there was no electricity or running water","He had to walk three kilometres every morning to get to his school","After school, he helped his father with the animals on the farm","He said that life was hard but that people were always willing to help each other"]'),
('ingles', 'eso', '{2}', '["Yesterday, my dog ran away from the garden while I was doing my homework","I went outside and called his name but he did not come back","I walked around the neighbourhood looking for him for almost an hour","Finally, I found him in the park playing happily with another dog","I was so relieved and I decided to fix the hole in the garden fence"]'),
('ingles', 'eso', '{2}', '["The science teacher took us on a field trip to the natural history museum","We saw dinosaur skeletons and fossils that were millions of years old","Our teacher explained how scientists use carbon dating to find the age of fossils","In the gift shop, I bought a small model of a Tyrannosaurus Rex","It was one of the most interesting school trips we have ever had"]'),
('ingles', 'eso', '{2}', '["My older sister studied very hard for her university entrance exam last year","She spent several months revising every evening after dinner","On the day of the exam, she was nervous but felt well prepared","A few weeks later, she received her results and had passed with excellent marks","She was accepted into her first choice university and our family celebrated together"]'),

-- 3º ESO: relative clauses and complex sentences
('ingles', 'eso', '{3}', '["Climate change is one of the biggest challenges that the world faces today","The burning of fossil fuels, which produces carbon dioxide, is a major cause","Global temperatures have risen significantly since the Industrial Revolution began","This warming, which affects ecosystems worldwide, is melting the polar ice caps","Scientists warn that urgent action is needed to reduce greenhouse gas emissions"]'),
('ingles', 'eso', '{3}', '["Marie Curie, who was born in Poland in 1867, moved to Paris to study science","She discovered two new elements, which she named polonium and radium","She was the first woman who won a Nobel Prize in Physics in 1903","She later won a second Nobel Prize in Chemistry, which made her truly exceptional","Her research, which laid the foundations of nuclear physics, continues to inspire scientists"]'),
('ingles', 'eso', '{3}', '["Social media, which billions of people use daily, has transformed the way we communicate","Platforms that allow instant messaging have made it easier to stay in touch with friends","However, there are risks that young people should be aware of when using social media","Cyberbullying, which can cause serious psychological harm, is one of the most concerning issues","It is important to think carefully about the information that you share online"]'),
('ingles', 'eso', '{3}', '["Volunteering is an activity that can benefit both the community and the volunteer","There are many organisations that need help with different types of projects","People who volunteer at food banks help families that are struggling financially","Environmental groups, which organise beach cleanups, welcome volunteers of all ages","The experience that you gain from volunteering looks great on a university application"]'),
('ingles', 'eso', '{3}', '["The Amazon rainforest, which covers a vast area of South America, is the largest on Earth","It contains millions of species that scientists have not yet fully identified","Indigenous communities, who have lived there for thousands of years, protect its biodiversity","Deforestation, which is driven by agriculture and logging, is destroying this vital ecosystem","The rainforest, which produces a large percentage of the world''s oxygen, must be preserved"]'),
('ingles', 'eso', '{3}', '["Artificial intelligence is a technology that is rapidly changing many aspects of our lives","Machines that can learn from data are now used in medicine and education","Virtual assistants, which respond to voice commands, help people with daily tasks","However, there are ethical concerns that society needs to address about this technology","Experts suggest that regulation is needed to ensure AI is used responsibly and fairly"]'),
('ingles', 'eso', '{3}', '["Shakespeare, who was born in Stratford-upon-Avon in 1564, is considered the greatest English writer","He wrote plays that explored universal themes like love, ambition and jealousy","Romeo and Juliet, which tells the story of two young lovers, is his most famous tragedy","The Globe Theatre, where many of his plays were performed, has been rebuilt in London","His works, which were written over four centuries ago, are still performed around the world"]'),
('ingles', 'eso', '{3}', '["Space exploration, which began with the launch of Sputnik in 1957, has advanced enormously","Neil Armstrong, who was the first person to walk on the moon, made history in 1969","The International Space Station, which orbits the Earth, is a laboratory in space","Mars, which is often called the Red Planet, is the next destination that agencies are targeting","The technology that is being developed for space travel could also benefit life on Earth"]'),
('ingles', 'eso', '{3}', '["The Olympic Games, which originated in ancient Greece, are the world''s biggest sporting event","The modern Olympics, which began in Athens in 1896, bring together athletes from every country","The Paralympic Games, which showcase the abilities of athletes with disabilities, run alongside them","Barcelona, which hosted the Games in 1992, was transformed by the event","The values that the Olympics promote include excellence, friendship and respect"]'),
('ingles', 'eso', '{3}', '["A healthy lifestyle requires a combination of good habits that work together","A balanced diet, which includes fruit, vegetables and protein, provides the energy we need","Regular exercise, which strengthens the heart and muscles, improves both physical and mental health","Sleep, which is essential for recovery and concentration, should last at least eight hours","Stress management, which can involve mindfulness or hobbies, is also an important factor"]'),

-- 4º ESO: conditionals and reported speech
('ingles', 'eso', '{4}', '["If the polar ice caps continue to melt, sea levels will rise dramatically","Coastal cities would be flooded if governments did not take action against climate change","Scientists have warned that we would face catastrophic consequences if temperatures rose by three degrees","They said that renewable energy was the key to solving the climate crisis","Experts reported that immediate investment in green technology could still make a difference"]'),
('ingles', 'eso', '{4}', '["The journalist asked the prime minister what measures the government was planning to take","The prime minister replied that they would invest heavily in public education and healthcare","She added that if the economy continued to grow they would create thousands of new jobs","A reporter asked whether taxes would be raised in the next budget","The prime minister explained that she could not make any promises until the figures were confirmed"]'),
('ingles', 'eso', '{4}', '["If I had studied harder for the exam, I would have got a much better mark","My teacher told me that I needed to improve my time management skills","She said that if I organised my revision better I would achieve the results I wanted","I promised her that I would create a study timetable and follow it every day","She replied that she was confident I would succeed if I put in the effort"]'),
('ingles', 'eso', '{4}', '["The scientist explained that if humans had not burned so many fossil fuels the atmosphere would be cleaner","She said that unless we changed our habits the planet would continue to warm","A student asked her what would happen if all countries switched to renewable energy","She replied that global emissions would decrease significantly within a decade","She added that it was not too late but that we needed to act immediately"]'),
('ingles', 'eso', '{4}', '["The coach told the team that they would win the championship if they trained harder","He explained that discipline and teamwork were more important than individual talent","He said that if they had followed his strategy in the last match they would not have lost","The captain replied that the team would commit to the new training plan starting immediately","After weeks of hard work, they won the final and the coach said he had never been prouder"]'),
('ingles', 'eso', '{4}', '["The doctor told the patient that if he did not reduce his stress levels his health would suffer","He recommended that the patient should exercise regularly and eat a balanced diet","He said that if he had come for a check-up earlier the problem could have been detected sooner","The patient asked the doctor what would happen if he followed all the advice carefully","The doctor replied that his health would improve significantly within a few months"]'),
('ingles', 'eso', '{4}', '["Martin Luther King said that he had a dream that one day all people would be treated equally","He told his audience that if they continued to fight peacefully they would achieve justice","He explained that freedom would never be achieved if people remained silent about injustice","His speeches inspired millions and he said that the time for change was always now","He was awarded the Nobel Peace Prize and declared that it belonged to every person fighting for equality"]'),
('ingles', 'eso', '{4}', '["The headteacher announced that the school would introduce a new anti-bullying policy","She said that if students witnessed bullying they should report it immediately","She explained that the school would provide support for both victims and those who bullied","A parent asked what would happen if the new measures did not reduce the incidents","The headteacher replied that they would review the policy and make adjustments if necessary"]'),
('ingles', 'eso', '{4}', '["If social media did not exist, young people would probably spend more time outdoors","A psychologist said that excessive screen time could lead to anxiety and sleep problems","She reported that teenagers who limited their social media use felt happier and more confident","She told parents that if they set reasonable boundaries their children would benefit","She added that technology was not inherently bad but that balance was absolutely essential"]'),
('ingles', 'eso', '{4}', '["The explorer said that if he had known how dangerous the expedition would be he might not have gone","He told reporters that the team had faced terrible storms and freezing temperatures","He explained that they would have reached the summit if the weather had not changed so suddenly","He said that despite the failure the experience had taught him more than any success ever could","He declared that he would attempt the expedition again because giving up was never an option"]');

-- ************************************************************
-- 6. LENGUA (2º, 3º, 4º ESO) — 30 historias
-- ************************************************************

INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES

-- 2º ESO: oración compuesta
('lengua', 'eso', '{2}', '["La oración compuesta contiene dos o más predicados con sus respectivos verbos","Las oraciones coordinadas se unen mediante nexos sin que una dependa de la otra","Las copulativas se unen con nexos como y, e, ni para sumar ideas","Las adversativas usan nexos como pero, sin embargo, para expresar contraste","Las disyuntivas presentan opciones excluyentes mediante los nexos o, u"]'),
('lengua', 'eso', '{2}', '["Las oraciones subordinadas dependen sintácticamente de una oración principal","Las subordinadas sustantivas funcionan como un sustantivo dentro de la oración principal","Pueden hacer de sujeto, como en la oración me gusta que vengas","También pueden funcionar como complemento directo en quiero que estudies más","Se introducen habitualmente mediante la conjunción que o un interrogativo indirecto"]'),
('lengua', 'eso', '{2}', '["Las oraciones subordinadas adjetivas funcionan como un adjetivo que complementa a un sustantivo","Se introducen por pronombres relativos como que, quien, el cual o donde","El antecedente es el sustantivo de la oración principal al que se refiere la subordinada","Las especificativas restringen el significado del antecedente sin ir entre comas","Las explicativas aportan información adicional y se escriben siempre entre comas"]'),
('lengua', 'eso', '{2}', '["Las subordinadas adverbiales funcionan como un adverbio dentro de la oración principal","Las temporales indican el momento de la acción con nexos como cuando o mientras","Las causales expresan la causa con nexos como porque o ya que","Las condicionales plantean una condición con si o a condición de que","Las finales indican el propósito de la acción con nexos como para que"]'),
('lengua', 'eso', '{2}', '["El texto expositivo tiene como objetivo informar sobre un tema de forma clara y objetiva","Se organiza con una introducción que presenta el tema de manera general","El desarrollo explica las ideas principales con datos y ejemplos concretos","La conclusión resume las ideas más importantes del texto expositivo","El lenguaje utilizado debe ser preciso, formal y sin opiniones personales"]'),
('lengua', 'eso', '{2}', '["El texto argumentativo tiene como finalidad defender una tesis con razones convincentes","La tesis es la idea principal que el autor quiere demostrar a lo largo del texto","Los argumentos son las razones que apoyan la tesis y le dan validez","Los contraargumentos anticipan objeciones del lector para refutarlas y fortalecer la posición","La conclusión refuerza la tesis inicial resumiendo los argumentos más sólidos"]'),
('lengua', 'eso', '{2}', '["Los complementos del verbo completan la información del predicado de la oración","El complemento directo recibe directamente la acción del verbo y se puede sustituir por lo","El complemento indirecto indica el destinatario de la acción y se sustituye por le","El complemento circunstancial aporta información sobre el lugar, tiempo o modo de la acción","El atributo acompaña a verbos copulativos como ser, estar y parecer"]'),
('lengua', 'eso', '{2}', '["El sujeto es la persona, animal o cosa de la que se dice algo en la oración","El sujeto concuerda siempre con el verbo en número y persona","Para identificarlo se cambia el número del verbo y se observa qué cambia","Existen oraciones impersonales que carecen de sujeto gramatical","El sujeto puede estar omitido o elíptico cuando se sobreentiende por el contexto"]'),
('lengua', 'eso', '{2}', '["Las figuras literarias son recursos del lenguaje que embellecen y enriquecen los textos","La metáfora sustituye un término real por uno imaginario con el que guarda semejanza","La comparación establece una relación de similitud usando los nexos como o cual","La hipérbole exagera una cualidad o circunstancia para crear un efecto expresivo","La personificación atribuye cualidades humanas a animales, objetos o ideas abstractas"]'),
('lengua', 'eso', '{2}', '["Los géneros literarios clasifican las obras según su forma y contenido","La narrativa cuenta una historia con personajes, espacio y tiempo definidos","La lírica expresa sentimientos y emociones del autor generalmente en verso","El género dramático presenta historias a través del diálogo entre personajes para ser representadas","El ensayo es un género que mezcla la exposición y la argumentación sobre temas variados"]'),

-- 3º ESO: Siglo de Oro
('lengua', 'eso', '{3}', '["El Siglo de Oro español abarca los siglos XVI y XVII y es la época de mayor esplendor literario","Durante el Renacimiento la literatura se inspiró en los modelos clásicos grecolatinos","Garcilaso de la Vega introdujo el soneto italianizante en la poesía castellana","Sus églogas presentan pastores idealizados que expresan sus sentimientos amorosos en la naturaleza","El tema del amor platónico y la belleza femenina son centrales en la poesía renacentista"]'),
('lengua', 'eso', '{3}', '["El Lazarillo de Tormes publicado en 1554 es la primera novela picaresca española","Narra en primera persona las aventuras de un mozo que sirve a diferentes amos","Cada amo representa un estamento social que el protagonista critica con ironía","La obra refleja la dura realidad social de la España del siglo XVI","El pícaro es un antihéroe que lucha por sobrevivir en una sociedad hipócrita"]'),
('lengua', 'eso', '{3}', '["Miguel de Cervantes escribió Don Quijote de la Mancha, publicado en dos partes en 1605 y 1615","Es considerada la primera novela moderna de la literatura universal","Don Quijote es un hidalgo que enloquece leyendo novelas de caballerías","Acompañado de su escudero Sancho Panza recorre La Mancha viviendo aventuras imaginarias","La obra es una parodia de los libros de caballerías pero también una profunda reflexión sobre la realidad"]'),
('lengua', 'eso', '{3}', '["Lope de Vega revolucionó el teatro español con su Arte nuevo de hacer comedias","Rompió las reglas clásicas de las tres unidades de tiempo, lugar y acción","Mezcló lo trágico y lo cómico e introdujo personajes populares como el gracioso","Fuenteovejuna cuenta la rebelión de un pueblo contra un comendador tirano","Lope escribió cientos de obras y es conocido como el Fénix de los Ingenios"]'),
('lengua', 'eso', '{3}', '["La poesía barroca se caracteriza por la complejidad formal y el juego con el lenguaje","Luis de Góngora fue el máximo representante del culteranismo con un estilo muy elaborado","Sus poemas están llenos de metáforas, hipérbatos y referencias mitológicas","Francisco de Quevedo representó el conceptismo con un estilo más directo e ingenioso","La rivalidad literaria entre Góngora y Quevedo es una de las más famosas de la literatura"]'),
('lengua', 'eso', '{3}', '["Calderón de la Barca fue el gran dramaturgo del Barroco español","La vida es sueño plantea la cuestión filosófica de si la vida es real o una ilusión","El protagonista Segismundo se debate entre la libertad y el destino impuesto","Los autos sacramentales son obras religiosas alegóricas que se representaban en la calle","El honor y el desengaño son temas recurrentes en todo el teatro de Calderón"]'),
('lengua', 'eso', '{3}', '["La mística española del siglo XVI busca la unión del alma con Dios a través de la poesía","Santa Teresa de Jesús escribió sobre su experiencia espiritual en prosa y verso","San Juan de la Cruz compuso poemas de una belleza lírica extraordinaria","El Cántico espiritual narra el encuentro del alma con Dios usando la alegoría amorosa","La literatura mística combina la profundidad religiosa con la excelencia artística"]'),
('lengua', 'eso', '{3}', '["El Romanticismo surge a finales del siglo XVIII como reacción contra el racionalismo ilustrado","Exalta los sentimientos, la libertad individual y la imaginación sobre la razón","En España llega con cierto retraso y tiene su apogeo en la primera mitad del siglo XIX","José de Espronceda es el poeta romántico español por excelencia con sus cantos a la libertad","Gustavo Adolfo Bécquer escribió las Rimas, poemas breves de gran sensibilidad y emoción"]'),
('lengua', 'eso', '{3}', '["El Realismo literario del siglo XIX busca reflejar fielmente la realidad social contemporánea","Los autores observan y describen la sociedad con objetividad y detalle minucioso","Benito Pérez Galdós es el gran novelista realista español con obras como Fortunata y Jacinta","Leopoldo Alas Clarín escribió La Regenta, considerada una obra maestra del Realismo","El Naturalismo llevó el Realismo al extremo incorporando las teorías científicas de la época"]'),
('lengua', 'eso', '{3}', '["La novela picaresca influyó en toda la narrativa europea posterior a su aparición","El Guzmán de Alfarache de Mateo Alemán continuó el modelo iniciado por el Lazarillo","El Buscón de Quevedo llevó la sátira social al extremo con su estilo mordaz","Los protagonistas picarescos recorren distintos ambientes sociales mostrando sus defectos","Este género creó el modelo del antihéroe que sobrevive con ingenio en un mundo hostil"]'),

-- 4º ESO: Generación del 98 y del 27
('lengua', 'eso', '{4}', '["La Generación del 98 surge tras la pérdida de las últimas colonias españolas en 1898","Los autores reflexionan sobre la decadencia de España y buscan la esencia de lo español","Miguel de Unamuno plantea conflictos existenciales entre la fe y la razón","Pío Baroja escribe novelas con protagonistas inconformistas que buscan su lugar en el mundo","Antonio Machado canta al paisaje castellano como símbolo del alma de España"]'),
('lengua', 'eso', '{4}', '["La Generación del 27 agrupa a poetas que combinan tradición y vanguardia en su obra","Federico García Lorca fusiona lo popular andaluz con la modernidad surrealista","Rafael Alberti evoluciona desde la poesía popular hasta el compromiso social y político","Pedro Salinas es el poeta del amor puro con obras como La voz a ti debida","Luis Cernuda expresa la frustración entre el deseo y la realidad en toda su obra"]'),
('lengua', 'eso', '{4}', '["Las vanguardias artísticas del siglo XX rompen radicalmente con las formas tradicionales","El surrealismo explora el mundo de los sueños y el subconsciente como fuente creativa","El futurismo exalta la velocidad, la tecnología y la vida moderna como valores artísticos","El dadaísmo rechaza toda lógica y convención proponiendo el azar como método creativo","En España Ramón Gómez de la Serna difundió el espíritu vanguardista con sus greguerías"]'),
('lengua', 'eso', '{4}', '["La Guerra Civil española tuvo un impacto devastador en la literatura y la cultura del país","Muchos escritores de la Generación del 27 tuvieron que exiliarse tras la victoria franquista","Federico García Lorca fue asesinado al comienzo de la guerra en agosto de 1936","Los poetas del exilio como Juan Ramón Jiménez continuaron su obra lejos de España","La literatura de posguerra en España reflejó la censura y la miseria de aquellos años"]'),
('lengua', 'eso', '{4}', '["La novela española de posguerra evoluciona desde el existencialismo al experimentalismo","La familia de Pascual Duarte de Camilo José Cela inauguró el tremendismo en 1942","Carmen Laforet ganó el primer premio Nadal con Nada, una novela de ambiente opresivo","En los años cincuenta el Realismo social denuncia las injusticias con obras como El Jarama","En los años sesenta Tiempo de silencio de Martín Santos renueva la técnica narrativa"]'),
('lengua', 'eso', '{4}', '["Federico García Lorca es uno de los poetas y dramaturgos más importantes del siglo XX","Su poesía combina la tradición del romancero con las imágenes del surrealismo","El Romancero gitano retrata el mundo gitano andaluz con un lenguaje metafórico brillante","En teatro creó obras como Bodas de sangre y La casa de Bernarda Alba","Su obra explora temas universales como la frustración, la pasión y la muerte"]'),
('lengua', 'eso', '{4}', '["Antonio Machado es uno de los poetas más queridos de la literatura española","Soledades es su primera obra donde explora los temas del tiempo y la melancolía","Campos de Castilla refleja el paisaje sobrio de Castilla como espejo del alma española","Su poesía evoluciona desde la introspección personal hacia una preocupación social y patriótica","Murió en el exilio en Collioure, Francia, en 1939 poco después de cruzar la frontera"]'),
('lengua', 'eso', '{4}', '["Miguel de Unamuno fue novelista, ensayista, poeta y filósofo de la Generación del 98","En Niebla el protagonista se rebela contra su propio autor cuestionando la realidad","San Manuel Bueno mártir plantea el drama de un sacerdote que ha perdido la fe","Su concepto de la intrahistoria busca la vida cotidiana del pueblo frente a los grandes hechos","Su obra refleja una constante lucha entre la razón y el sentimiento vital"]'),
('lengua', 'eso', '{4}', '["El teatro español del siglo XX experimentó una profunda renovación a partir de los años sesenta","Antonio Buero Vallejo escribió Historia de una escalera como metáfora de la frustración social","Alfonso Sastre representó el teatro comprometido con la denuncia política y social","Fernando Arrabal desarrolló el teatro del absurdo con obras provocadoras y experimentales","En la actualidad el teatro español combina la herencia clásica con las nuevas formas escénicas"]'),
('lengua', 'eso', '{4}', '["La literatura hispanoamericana del siglo XX alcanzó un reconocimiento mundial extraordinario","El boom latinoamericano de los años sesenta llevó la narrativa en español a todo el mundo","Gabriel García Márquez creó Cien años de soledad como obra cumbre del realismo mágico","Mario Vargas Llosa exploró la sociedad peruana con novelas de gran complejidad estructural","Julio Cortázar revolucionó la forma de narrar con Rayuela y sus cuentos fantásticos"]');

-- ************************************************************
-- 7. MATEMÁTICAS (1º: 1 historia, 2º-4º: 10 cada) — 31 historias
-- ************************************************************

INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES

-- 1º ESO: 1 historia
('matematicas', 'eso', '{1}', '["Los números enteros incluyen los positivos, los negativos y el cero","Se representan sobre una recta numérica donde el cero ocupa el centro","Los números a la derecha del cero son positivos y a la izquierda negativos","Para sumar dos enteros del mismo signo se suman sus valores absolutos y se conserva el signo","Para sumar dos enteros de distinto signo se restan los valores absolutos y se pone el signo del mayor"]'),

-- 2º ESO
('matematicas', 'eso', '{2}', '["Una ecuación de primer grado tiene una sola incógnita de exponente uno","Para resolverla se aísla la incógnita en un lado de la igualdad","Se pasan los términos con incógnita a un miembro y los independientes al otro","Los términos cambian de signo al pasar de un miembro a otro de la ecuación","Finalmente se divide ambos miembros entre el coeficiente de la incógnita"]'),
('matematicas', 'eso', '{2}', '["Un sistema de ecuaciones lineales está formado por dos ecuaciones con dos incógnitas","El método de sustitución consiste en despejar una incógnita en una ecuación","Después se sustituye la expresión obtenida en la otra ecuación","Así se obtiene una ecuación con una sola incógnita que se puede resolver fácilmente","El valor hallado se sustituye en la primera ecuación para encontrar la otra incógnita"]'),
('matematicas', 'eso', '{2}', '["El teorema de Pitágoras se aplica a los triángulos rectángulos","Establece que el cuadrado de la hipotenusa es igual a la suma de los cuadrados de los catetos","La hipotenusa es el lado más largo, opuesto al ángulo recto","Si conocemos dos lados del triángulo podemos calcular el tercero con este teorema","Tiene aplicaciones prácticas en la construcción, la navegación y el diseño"]'),
('matematicas', 'eso', '{2}', '["La proporcionalidad directa relaciona dos magnitudes que crecen o decrecen juntas","Si una magnitud se duplica la otra también se duplica","La constante de proporcionalidad es el cociente entre las dos magnitudes","La proporcionalidad inversa se da cuando al aumentar una magnitud la otra disminuye","En este caso el producto de ambas magnitudes es siempre constante"]'),
('matematicas', 'eso', '{2}', '["Una función es una relación que asocia a cada valor de x un único valor de y","La variable independiente se representa en el eje horizontal de coordenadas","La variable dependiente se representa en el eje vertical de coordenadas","La gráfica de una función lineal es una línea recta que pasa por el origen","La pendiente de la recta indica cómo de rápido crece o decrece la función"]'),
('matematicas', 'eso', '{2}', '["Las potencias expresan la multiplicación repetida de un número por sí mismo","La base es el número que se multiplica y el exponente indica cuántas veces","Cualquier número elevado a cero es igual a uno según la definición","El producto de potencias con la misma base se resuelve sumando los exponentes","El cociente de potencias con la misma base se resuelve restando los exponentes"]'),
('matematicas', 'eso', '{2}', '["Los polígonos regulares tienen todos sus lados y ángulos iguales entre sí","El triángulo equilátero tiene tres lados iguales y tres ángulos de sesenta grados","El cuadrado tiene cuatro lados iguales y cuatro ángulos de noventa grados","El hexágono regular tiene seis lados iguales y se puede descomponer en seis triángulos","El área de un polígono regular se calcula multiplicando su perímetro por la apotema y dividiendo entre dos"]'),
('matematicas', 'eso', '{2}', '["La estadística se ocupa de recoger, organizar y analizar datos numéricos","La media aritmética se calcula sumando todos los datos y dividiendo entre el total","La mediana es el valor central cuando los datos están ordenados de menor a mayor","La moda es el dato que más veces se repite en el conjunto de valores","Estas tres medidas de tendencia central resumen la información contenida en los datos"]'),
('matematicas', 'eso', '{2}', '["Los números racionales son aquellos que se pueden expresar como una fracción","Incluyen a los números enteros, que se pueden escribir con denominador uno","Los decimales exactos y los periódicos también son números racionales","Los números irracionales como pi no se pueden expresar como fracción","Los números racionales e irracionales juntos forman el conjunto de los números reales"]'),
('matematicas', 'eso', '{2}', '["La semejanza de figuras se da cuando tienen la misma forma pero diferente tamaño","Dos triángulos son semejantes si tienen los tres ángulos iguales","La razón de semejanza es el cociente entre los lados correspondientes de ambas figuras","El teorema de Tales establece que rectas paralelas cortando a dos secantes producen segmentos proporcionales","La semejanza se aplica en la elaboración de mapas, planos y maquetas a escala"]'),

-- 3º ESO
('matematicas', 'eso', '{3}', '["Una ecuación de segundo grado tiene la forma ax al cuadrado más bx más c igual a cero","El discriminante es b al cuadrado menos cuatro por a por c y determina el número de soluciones","Si el discriminante es positivo la ecuación tiene dos soluciones reales distintas","Si el discriminante es cero la ecuación tiene una solución doble","Si el discriminante es negativo la ecuación no tiene soluciones reales"]'),
('matematicas', 'eso', '{3}', '["Las sucesiones numéricas son listas ordenadas de números que siguen una regla","En una progresión aritmética la diferencia entre términos consecutivos es constante","El término general permite calcular cualquier término sin necesidad de conocer los anteriores","La suma de los n primeros términos se calcula con la fórmula de Gauss","Las progresiones aritméticas aparecen en situaciones cotidianas como el ahorro periódico"]'),
('matematicas', 'eso', '{3}', '["Los polinomios son expresiones algebraicas formadas por la suma de varios monomios","El grado del polinomio es el mayor exponente de la variable que aparece","Para sumar polinomios se agrupan y suman los monomios del mismo grado","La multiplicación de polinomios se realiza multiplicando cada término por todos los del otro","La factorización consiste en descomponer un polinomio como producto de factores más simples"]'),
('matematicas', 'eso', '{3}', '["Las funciones cuadráticas tienen la forma y igual a ax al cuadrado más bx más c","Su gráfica es una parábola que se abre hacia arriba si a es positivo","El vértice de la parábola es el punto máximo o mínimo de la función","El eje de simetría es una recta vertical que pasa por el vértice","Las raíces o ceros de la función son los puntos donde la parábola corta al eje horizontal"]'),
('matematicas', 'eso', '{3}', '["La trigonometría estudia las relaciones entre los ángulos y los lados de los triángulos","El seno de un ángulo es la razón entre el cateto opuesto y la hipotenusa","El coseno es la razón entre el cateto contiguo y la hipotenusa","La tangente es la razón entre el cateto opuesto y el cateto contiguo","Estas razones permiten calcular distancias y alturas inaccesibles de forma indirecta"]'),
('matematicas', 'eso', '{3}', '["La geometría analítica permite estudiar figuras geométricas mediante coordenadas","Un punto en el plano se representa mediante un par ordenado de coordenadas","La distancia entre dos puntos se calcula aplicando el teorema de Pitágoras a las coordenadas","El punto medio de un segmento se obtiene haciendo la media de las coordenadas de sus extremos","La ecuación de una recta puede expresarse en forma punto-pendiente o en forma general"]'),
('matematicas', 'eso', '{3}', '["La probabilidad clásica de un suceso es el cociente entre casos favorables y casos posibles","Un experimento aleatorio es aquel cuyo resultado no se puede predecir con certeza","El espacio muestral es el conjunto de todos los resultados posibles del experimento","Dos sucesos son incompatibles si no pueden ocurrir al mismo tiempo","La probabilidad de la unión de sucesos incompatibles es la suma de sus probabilidades"]'),
('matematicas', 'eso', '{3}', '["Las inecuaciones son desigualdades algebraicas que contienen una o más incógnitas","Se resuelven de forma similar a las ecuaciones pero con una regla especial","Al multiplicar o dividir ambos miembros por un número negativo se invierte la desigualdad","La solución de una inecuación es un conjunto de valores representado como un intervalo","Los intervalos pueden ser abiertos, cerrados o semiabiertos según incluyan o no los extremos"]'),
('matematicas', 'eso', '{3}', '["Los cuerpos geométricos se clasifican en poliedros y cuerpos de revolución","Los poliedros tienen todas sus caras planas como el cubo o el tetraedro","Los prismas tienen dos bases paralelas e iguales unidas por caras rectangulares","Las pirámides tienen una base poligonal y sus caras laterales son triángulos que convergen en un vértice","Los cuerpos de revolución como el cilindro y el cono se generan al girar una figura plana"]'),
('matematicas', 'eso', '{3}', '["Los logaritmos son la operación inversa de las potencias","El logaritmo en base b de un número n es el exponente al que hay que elevar b para obtener n","Los logaritmos decimales usan base diez y se utilizan mucho en ciencia e ingeniería","Los logaritmos naturales usan como base el número e que vale aproximadamente dos coma siete","Las propiedades de los logaritmos permiten simplificar multiplicaciones y divisiones"]'),

-- 4º ESO
('matematicas', 'eso', '{4}', '["Los números complejos amplían los números reales para incluir raíces de números negativos","La unidad imaginaria i se define como la raíz cuadrada de menos uno","Un número complejo tiene la forma a más bi, donde a es la parte real y b la imaginaria","Los números complejos se pueden representar como puntos en un plano cartesiano","La suma de complejos se realiza sumando las partes reales y las imaginarias por separado"]'),
('matematicas', 'eso', '{4}', '["Los vectores son magnitudes que tienen módulo, dirección y sentido","Se representan gráficamente como flechas en el plano o en el espacio","La suma de vectores se puede realizar gráficamente por la regla del paralelogramo","El producto de un escalar por un vector cambia su módulo manteniendo o invirtiendo su sentido","Dos vectores son perpendiculares cuando su producto escalar es igual a cero"]'),
('matematicas', 'eso', '{4}', '["La combinatoria estudia las formas de agrupar y ordenar elementos de un conjunto","Las permutaciones son agrupaciones donde importa el orden de los elementos","Las combinaciones son agrupaciones donde no importa el orden de los elementos","El factorial de un número natural n es el producto de todos los enteros desde uno hasta n","El triángulo de Pascal permite calcular rápidamente los números combinatorios"]'),
('matematicas', 'eso', '{4}', '["Una función exponencial tiene la variable en el exponente y crece de forma muy rápida","Si la base es mayor que uno la función es creciente y se aleja rápidamente del eje","Si la base está entre cero y uno la función es decreciente y se aproxima al eje","La función exponencial modela fenómenos como el crecimiento de poblaciones","La función logarítmica es la inversa de la exponencial y crece de forma cada vez más lenta"]'),
('matematicas', 'eso', '{4}', '["La estadística bidimensional estudia la relación entre dos variables cuantitativas","Una nube de puntos representa gráficamente los pares de valores de ambas variables","La recta de regresión es la línea que mejor se ajusta a la nube de puntos","El coeficiente de correlación mide la intensidad de la relación lineal entre las variables","Un coeficiente cercano a uno indica una fuerte relación directa y cercano a menos uno inversa"]'),
('matematicas', 'eso', '{4}', '["Los límites de funciones estudian el comportamiento de una función cerca de un punto","Si al acercarnos a un valor la función se aproxima a un número concreto ese es el límite","Una función es continua en un punto si el límite coincide con el valor de la función","Las asíntotas son rectas a las que la gráfica se aproxima sin llegar a tocarlas","Las asíntotas pueden ser horizontales, verticales u oblicuas según su orientación"]'),
('matematicas', 'eso', '{4}', '["La derivada de una función mide la tasa de cambio instantánea en cada punto","Geométricamente representa la pendiente de la recta tangente a la curva en ese punto","Si la derivada es positiva la función es creciente en ese intervalo","Si la derivada es negativa la función es decreciente en ese intervalo","Los puntos donde la derivada se anula son candidatos a ser máximos o mínimos de la función"]'),
('matematicas', 'eso', '{4}', '["Las distribuciones de probabilidad asignan probabilidades a los posibles resultados de un experimento","La distribución binomial modela experimentos con solo dos resultados posibles como éxito o fracaso","Se aplica cuando se repite un mismo experimento independiente un número fijo de veces","La distribución normal tiene forma de campana simétrica centrada en la media","Muchos fenómenos naturales como la estatura o el peso siguen aproximadamente una distribución normal"]'),
('matematicas', 'eso', '{4}', '["Las matrices son tablas rectangulares de números organizados en filas y columnas","Se pueden sumar dos matrices del mismo tamaño sumando sus elementos correspondientes","El producto de matrices requiere que el número de columnas de la primera coincida con las filas de la segunda","La matriz identidad es el elemento neutro de la multiplicación de matrices cuadradas","Las matrices tienen aplicaciones en informática, economía y resolución de sistemas de ecuaciones"]'),
('matematicas', 'eso', '{4}', '["Las funciones trigonométricas extienden las razones trigonométricas a cualquier ángulo real","La función seno es periódica con periodo dos pi y oscila entre menos uno y uno","La función coseno también es periódica con periodo dos pi y es idéntica al seno desplazado","La función tangente tiene periodo pi y presenta asíntotas verticales donde el coseno vale cero","Las funciones trigonométricas modelan fenómenos periódicos como las ondas sonoras y las mareas"]');

-- ************************************************************
-- 8. MÚSICA (2º, 3º, 4º ESO) — 30 historias
-- ************************************************************

INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES

-- 2º ESO
('musica', 'eso', '{2}', '["La música del Renacimiento se desarrolló durante los siglos XV y XVI en Europa","La polifonía vocal alcanzó su máximo esplendor con compositores como Palestrina","Las voces se entrelazan de forma armoniosa creando texturas complejas y equilibradas","La imprenta musical permitió difundir las partituras por todo el continente","La música dejó de ser exclusivamente religiosa y surgieron formas profanas como el madrigal"]'),
('musica', 'eso', '{2}', '["La música del Barroco abarca desde 1600 hasta 1750 aproximadamente","Se caracteriza por el contraste de dinámicas y la ornamentación elaborada","Bach es uno de los compositores más importantes del periodo con sus fugas y corales","Vivaldi compuso Las cuatro estaciones, uno de los conciertos más conocidos de la historia","La ópera nació en este periodo como una fusión de música, teatro y poesía"]'),
('musica', 'eso', '{2}', '["Los intervalos musicales miden la distancia en altura entre dos notas","Un intervalo de segunda es la distancia entre dos notas consecutivas como Do y Re","Un intervalo de tercera abarca tres notas y puede ser mayor o menor","La octava es el intervalo que separa dos notas del mismo nombre a diferente altura","Los intervalos consonantes suenan agradables y los disonantes crean tensión"]'),
('musica', 'eso', '{2}', '["La tonalidad es el sistema que organiza las notas alrededor de una nota principal llamada tónica","Las escalas mayores tienen un carácter alegre y luminoso","Las escalas menores transmiten una sensación más melancólica o misteriosa","La armadura al principio del pentagrama indica los sostenidos o bemoles de la tonalidad","La modulación es el cambio de tonalidad durante una pieza musical"]'),
('musica', 'eso', '{2}', '["La guitarra española es un instrumento de cuerda pulsada con seis cuerdas","El cuerpo de la guitarra amplifica las vibraciones producidas por las cuerdas","Los trastes en el mástil permiten producir diferentes notas al presionar las cuerdas","La guitarra clásica se toca con los dedos mientras la acústica puede tocarse con púa","Es uno de los instrumentos más populares y versátiles del mundo"]'),
('musica', 'eso', '{2}', '["El compás musical organiza los pulsos en grupos regulares con acentos periódicos","El compás de dos por cuatro tiene dos tiempos y se usa mucho en marchas y polcas","El compás de tres por cuatro tiene tres tiempos y es característico del vals","El compás de cuatro por cuatro es el más común en la música popular actual","La cifra superior indica el número de tiempos y la inferior el valor de cada tiempo"]'),
('musica', 'eso', '{2}', '["La forma musical es la estructura que organiza las diferentes secciones de una obra","La forma binaria tiene dos secciones contrastantes que se representan como A y B","La forma ternaria añade una repetición de la primera sección quedando como A B A","El rondó alterna un estribillo con diferentes estrofas siguiendo el esquema A B A C A","La forma sonata es más compleja y consta de exposición, desarrollo y reexposición"]'),
('musica', 'eso', '{2}', '["La voz humana es el instrumento musical más natural y expresivo que existe","Se clasifica según su registro en soprano, mezzosoprano, contralto, tenor, barítono y bajo","Las voces femeninas suelen ser más agudas y las masculinas más graves","Un coro combina diferentes voces para crear una sonoridad rica y envolvente","El cambio de voz en la adolescencia afecta especialmente a las voces masculinas"]'),
('musica', 'eso', '{2}', '["Los instrumentos de viento metal producen el sonido por la vibración de los labios","La trompeta es el instrumento más agudo de la familia con un sonido brillante","El trombón utiliza una vara deslizante para cambiar la longitud del tubo y las notas","La tuba es el instrumento más grave de la familia y proporciona el bajo de la orquesta","La trompa tiene un tubo enrollado muy largo y produce un sonido cálido y redondo"]'),
('musica', 'eso', '{2}', '["La dinámica musical se refiere a los cambios de volumen o intensidad del sonido","Piano significa suave y forte significa fuerte en la terminología musical italiana","El crescendo es un aumento gradual de la intensidad sonora","El diminuendo es una disminución progresiva del volumen del sonido","Los matices dinámicos aportan expresividad y emoción a la interpretación musical"]'),

-- 3º ESO
('musica', 'eso', '{3}', '["La música del Clasicismo se desarrolló durante la segunda mitad del siglo XVIII","Se caracteriza por la claridad, el equilibrio y la elegancia de las formas musicales","Haydn es considerado el padre de la sinfonía y del cuarteto de cuerda","Mozart fue un genio precoz que compuso óperas, sinfonías y conciertos de extraordinaria belleza","La orquesta clásica se consolidó como la agrupación instrumental más importante"]'),
('musica', 'eso', '{3}', '["Beethoven es una figura clave en la transición del Clasicismo al Romanticismo musical","Sus primeras obras siguen el estilo clásico de Haydn y Mozart","A partir de la Tercera Sinfonía, la Heroica, su música adquiere una fuerza expresiva nueva","La progresiva sordera que sufrió no le impidió componer sus obras más revolucionarias","La Novena Sinfonía con su Oda a la Alegría es considerada una cumbre de la música universal"]'),
('musica', 'eso', '{3}', '["La música del Romanticismo abarca gran parte del siglo XIX","Los compositores románticos expresan emociones intensas y sentimientos personales","Chopin revolucionó la música para piano con sus nocturnos, valses y polonesas","La ópera romántica alcanzó su apogeo con Verdi en Italia y Wagner en Alemania","El nacionalismo musical buscó reflejar la identidad cultural de cada pueblo en su música"]'),
('musica', 'eso', '{3}', '["La textura musical describe cómo se combinan las distintas líneas melódicas en una obra","La monodia es una sola línea melódica sin acompañamiento armónico","La homofonía presenta una melodía principal acompañada por acordes de soporte","La polifonía combina varias melodías independientes que suenan simultáneamente","La textura de una obra influye enormemente en su carácter y su sonoridad global"]'),
('musica', 'eso', '{3}', '["La armonía estudia cómo se combinan los sonidos simultáneos formando acordes","Un acorde se forma al tocar tres o más notas diferentes al mismo tiempo","Los acordes mayores tienen un sonido alegre y los menores un sonido más triste","La progresión de acordes es la sucesión ordenada que da sentido a una pieza musical","La cadencia es una secuencia de acordes que produce sensación de reposo o conclusión"]'),
('musica', 'eso', '{3}', '["El flamenco es un arte musical nacido en Andalucía con influencias gitanas y árabes","Combina tres elementos fundamentales: el cante, el toque de guitarra y el baile","Los palos son las diferentes formas o estilos del flamenco como la bulería o la soleá","Cada palo tiene su propio compás, melodía y carácter expresivo","El flamenco fue declarado Patrimonio Inmaterial de la Humanidad por la UNESCO en 2010"]'),
('musica', 'eso', '{3}', '["La música programática del Romanticismo busca evocar imágenes o contar una historia","El poema sinfónico es una obra orquestal que desarrolla un argumento literario o pictórico","Liszt fue el creador del poema sinfónico como forma musical independiente","Strauss compuso poemas sinfónicos muy descriptivos como Así habló Zaratustra","La música absoluta, en cambio, no pretende representar nada fuera de sí misma"]'),
('musica', 'eso', '{3}', '["El jazz nació a principios del siglo XX en Nueva Orleans con raíces afroamericanas","Combina elementos del blues, el gospel y la música europea","La improvisación es uno de los rasgos más característicos del jazz","Louis Armstrong fue uno de los primeros grandes músicos del jazz con su trompeta","El swing, el bebop y el jazz fusión son algunos de los estilos que han surgido dentro del género"]'),
('musica', 'eso', '{3}', '["La música electrónica utiliza instrumentos y dispositivos electrónicos para crear sonido","El sintetizador es un instrumento que genera sonidos de forma artificial","En los años setenta grupos como Kraftwerk fueron pioneros de la música electrónica","Los disc jockeys mezclan pistas pregrabadas para crear nuevas composiciones en directo","La producción musical digital ha democratizado la creación y distribución de la música"]'),
('musica', 'eso', '{3}', '["La banda sonora es la música compuesta específicamente para acompañar una película","Refuerza las emociones de las escenas y ayuda a narrar la historia visualmente","John Williams compuso las bandas sonoras de sagas como Star Wars e Indiana Jones","Ennio Morricone es famoso por sus melodías para películas del oeste como El bueno, el feo y el malo","Hans Zimmer ha creado bandas sonoras épicas para películas como Interstellar y El caballero oscuro"]'),

-- 4º ESO
('musica', 'eso', '{4}', '["La música del siglo XX rompe con las convenciones tonales del periodo anterior","El impresionismo musical de Debussy busca evocar atmósferas y sensaciones con nuevos timbres","El expresionismo de Schoenberg explora las emociones extremas mediante la disonancia","El dodecafonismo organiza las doce notas de la escala cromática en series sin jerarquía tonal","Stravinsky revolucionó el ritmo y la instrumentación con obras como La consagración de la primavera"]'),
('musica', 'eso', '{4}', '["El rock and roll surgió en Estados Unidos en los años cincuenta como música juvenil rebelde","Elvis Presley y Chuck Berry fueron figuras clave en la popularización del nuevo género","En los años sesenta los Beatles revolucionaron la música pop con su creatividad e innovación","Los Rolling Stones representaron una versión más dura y provocadora del rock","El rock se diversificó en múltiples subgéneros como el punk, el heavy metal y el rock alternativo"]'),
('musica', 'eso', '{4}', '["El blues es un género musical nacido de la experiencia de la comunidad afroamericana","Sus letras expresan tristeza, dolor y esperanza con una estructura de doce compases","La guitarra y la armónica son instrumentos esenciales en la interpretación del blues","Robert Johnson y B.B. King son dos de los artistas más influyentes del género","El blues es la raíz de la que nacieron el rock, el jazz y el soul"]'),
('musica', 'eso', '{4}', '["El hip hop nació en los barrios del Bronx de Nueva York a finales de los años setenta","Incluye cuatro elementos fundamentales: el rap, el DJ, el breakdance y el grafiti","El rap consiste en recitar rimas con ritmo sobre una base musical","Los DJs crean las bases usando tocadiscos y técnicas como el scratching","El hip hop se ha convertido en un fenómeno cultural global que influye en la moda y el arte"]'),
('musica', 'eso', '{4}', '["La industria musical ha experimentado enormes cambios con la llegada de la tecnología digital","Los formatos físicos como el vinilo y el CD han sido sustituidos por la música en streaming","Las plataformas digitales permiten a los artistas distribuir su música sin necesidad de una discográfica","Los algoritmos de recomendación influyen en los hábitos de escucha de los usuarios","El debate sobre los derechos de autor y la remuneración justa a los artistas sigue abierto"]'),
('musica', 'eso', '{4}', '["La música minimalista surgió en Estados Unidos en los años sesenta como reacción al serialismo","Se basa en la repetición de patrones musicales breves que cambian de forma gradual y sutil","Steve Reich y Philip Glass son dos de los compositores minimalistas más reconocidos","Las obras minimalistas pueden durar horas creando un efecto hipnótico en el oyente","Esta corriente ha influido en la música electrónica, el ambient y las bandas sonoras de cine"]'),
('musica', 'eso', '{4}', '["La música latina ha conquistado el panorama musical internacional en las últimas décadas","La salsa fusiona ritmos cubanos con jazz y otros géneros creando una música bailable y festiva","El reggaetón nació en Puerto Rico combinando reggae, hip hop y ritmos caribeños","Artistas como Shakira y Bad Bunny han llevado la música en español a las listas mundiales","La diversidad de géneros latinos refleja la riqueza cultural de Hispanoamérica"]'),
('musica', 'eso', '{4}', '["La música experimental busca explorar nuevos sonidos y formas más allá de lo convencional","John Cage compuso una pieza llamada 4 minutos 33 segundos que consiste enteramente en silencio","La música concreta utiliza sonidos grabados del entorno real como materia prima musical","La música aleatoria deja algunos elementos de la composición al azar o a la decisión del intérprete","Estas corrientes han ampliado nuestra concepción de lo que puede considerarse música"]'),
('musica', 'eso', '{4}', '["El reggae nació en Jamaica en los años sesenta como expresión de la cultura rastafari","Bob Marley es el artista más emblemático del reggae y un símbolo de paz y justicia social","El ritmo característico del reggae acentúa los tiempos débiles del compás","Las letras suelen tratar temas sociales, espirituales y de protesta contra la opresión","El reggae ha influido en géneros posteriores como el dub, el dancehall y el reggaetón"]'),
('musica', 'eso', '{4}', '["La ópera es un género que combina música, canto, teatro y artes visuales en una sola obra","Nació en Italia a finales del siglo XVI como intento de revivir el drama griego antiguo","Las voces de los cantantes de ópera deben proyectarse sin amplificación sobre una orquesta","Verdi y Puccini crearon óperas italianas de gran belleza como Aida y La bohème","Wagner concibió la ópera como una obra de arte total que integraba todas las disciplinas artísticas"]');

-- ************************************************************
-- 9. ECONOMÍA — 4º ESO — 10 historias
-- ************************************************************

INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('economia', 'eso', '{4}', '["La elasticidad de la demanda mide cómo reacciona la cantidad demandada ante un cambio de precio","Si un pequeño aumento de precio provoca una gran caída en la demanda esta es elástica","Los bienes de primera necesidad suelen tener una demanda inelástica al precio","Los bienes de lujo tienden a tener una demanda más elástica porque son prescindibles","Conocer la elasticidad ayuda a las empresas a fijar sus precios de forma estratégica"]'),
('economia', 'eso', '{4}', '["El oligopolio es un mercado dominado por un pequeño número de empresas oferentes","Las decisiones de cada empresa afectan directamente a las demás del mercado","Las empresas oligopolistas pueden competir en precios o llegar a acuerdos llamados cárteles","Los cárteles son ilegales porque fijan precios artificialmente altos perjudicando al consumidor","Las autoridades de competencia vigilan estos mercados para garantizar la libre competencia"]'),
('economia', 'eso', '{4}', '["La política fiscal es el conjunto de decisiones del gobierno sobre ingresos y gastos públicos","Una política fiscal expansiva aumenta el gasto público o reduce impuestos para estimular la economía","Una política fiscal restrictiva reduce el gasto o sube impuestos para controlar la inflación","El multiplicador fiscal explica cómo un aumento del gasto genera un efecto mayor en la producción","El equilibrio entre estimular el crecimiento y controlar el déficit es un reto constante"]'),
('economia', 'eso', '{4}', '["La política monetaria es gestionada por el banco central para controlar la cantidad de dinero","Si el banco central baja los tipos de interés el crédito se abarata y aumenta el consumo","Si sube los tipos de interés el crédito se encarece y se frena la inflación","La emisión de dinero sin respaldo puede provocar hiperinflación y destruir el valor de la moneda","El objetivo principal de la política monetaria es mantener la estabilidad de precios"]'),
('economia', 'eso', '{4}', '["La responsabilidad social corporativa es el compromiso voluntario de las empresas con la sociedad","Incluye prácticas respetuosas con el medio ambiente y con los derechos de los trabajadores","Las empresas socialmente responsables suelen tener mejor imagen y fidelización de clientes","Invertir en sostenibilidad puede generar beneficios económicos a largo plazo para la empresa","Los consumidores cada vez valoran más que las empresas actúen de forma ética y responsable"]'),
('economia', 'eso', '{4}', '["El comercio electrónico ha transformado la forma en que compramos y vendemos productos","Las tiendas en línea permiten comparar precios y acceder a productos de todo el mundo","El consumidor tiene derecho a devolver los productos comprados por internet en un plazo determinado","La logística de distribución es un factor clave para el éxito del comercio electrónico","La ciberseguridad es fundamental para proteger los datos personales y bancarios de los compradores"]'),
('economia', 'eso', '{4}', '["Las cooperativas son empresas donde los socios son al mismo tiempo propietarios y trabajadores","Se rigen por principios democráticos donde cada socio tiene un voto independientemente de su capital","Los beneficios se reparten entre los socios en función de su participación en el trabajo","Las cooperativas fomentan valores como la solidaridad, la igualdad y la participación","Mondragón es uno de los mayores grupos cooperativos del mundo y tiene su sede en el País Vasco"]'),
('economia', 'eso', '{4}', '["La economía circular propone un modelo alternativo al sistema lineal de producir, usar y tirar","Se basa en diseñar productos para que puedan ser reparados, reutilizados o reciclados","Los residuos de un proceso productivo se convierten en materias primas para otro","Este modelo reduce el consumo de recursos naturales y la generación de residuos","Empresas y gobiernos están adoptando la economía circular como estrategia de sostenibilidad"]'),
('economia', 'eso', '{4}', '["La desigualdad económica mide las diferencias de renta y riqueza entre personas o países","El coeficiente de Gini es un indicador que mide la desigualdad en la distribución de la renta","Un valor de cero representa igualdad perfecta y un valor de uno desigualdad máxima","Las políticas redistributivas como los impuestos progresivos buscan reducir estas diferencias","La educación y la igualdad de oportunidades son factores clave para combatir la desigualdad"]'),
('economia', 'eso', '{4}', '["Las criptomonedas son monedas digitales que funcionan de forma descentralizada sin un banco central","El Bitcoin fue la primera criptomoneda creada en 2009 por un autor anónimo conocido como Satoshi Nakamoto","La tecnología blockchain registra todas las transacciones de forma segura y transparente","Las criptomonedas son muy volátiles y su valor puede cambiar drásticamente en poco tiempo","Los reguladores debaten cómo supervisar estas monedas para proteger a los inversores"]');

-- ************************************************************
-- 10. LATÍN — 4º ESO — 10 historias
-- ************************************************************

INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('latin', 'eso', '{4}', '["Augusto fue el primer emperador de Roma y gobernó desde el 27 a.C. hasta el 14 d.C.","Tras la muerte de Julio César, venció a Marco Antonio en la batalla de Accio","Instauró un periodo de paz y prosperidad conocido como la Pax Romana","Reformó la administración del imperio y embelleció la ciudad de Roma","Se dice que afirmó haber encontrado una ciudad de ladrillo y dejar una de mármol"]'),
('latin', 'eso', '{4}', '["El derecho romano es uno de los legados más importantes de la civilización romana","Las Doce Tablas fueron la primera codificación escrita de las leyes romanas","Establecían normas sobre propiedad, herencia, familia y procedimientos judiciales","El jurista Justiniano recopiló todo el derecho romano en el Corpus Iuris Civilis","Estos principios jurídicos son la base de los sistemas legales de gran parte de Europa"]'),
('latin', 'eso', '{4}', '["La educación en Roma estaba dividida en tres niveles según la edad del alumno","El ludus magister enseñaba a leer, escribir y contar a los niños más pequeños","El grammaticus instruía a los adolescentes en literatura griega y latina","El rhetor preparaba a los jóvenes de familias ricas en el arte de la oratoria","Solo los hijos varones de familias acomodadas accedían a los niveles superiores de educación"]'),
('latin', 'eso', '{4}', '["Ovidio fue un gran poeta romano conocido por sus Metamorfosis","Esta obra recopila más de doscientos mitos de la tradición grecolatina","Narra las transformaciones de dioses, héroes y mortales en otros seres","La historia de Apolo y Dafne, convertida en laurel, es una de las más célebres","Las Metamorfosis han inspirado a pintores, escultores y escritores durante siglos"]'),
('latin', 'eso', '{4}', '["La alimentación romana variaba mucho según la clase social del individuo","Los pobres se alimentaban principalmente de pan, gachas de cereales y legumbres","Los ricos celebraban grandes banquetes con platos elaborados y productos exóticos","El garum era una salsa de pescado fermentado muy apreciada en toda la cocina romana","El triclinium era la sala del comedor donde los comensales se reclinaban para comer"]'),
('latin', 'eso', '{4}', '["El latín ha dejado numerosas expresiones que seguimos usando en la actualidad","Carpe diem significa aprovecha el día y nos invita a vivir el momento presente","Veni, vidi, vici fue la frase con la que César anunció una rápida victoria militar","In dubio pro reo es un principio jurídico que significa que la duda favorece al acusado","Estas expresiones demuestran la pervivencia del latín en nuestra lengua y cultura"]'),
('latin', 'eso', '{4}', '["Los acueductos romanos de Hispania son testimonio de la ingeniería romana en la Península","El acueducto de Segovia tiene más de ciento sesenta arcos y se conserva casi intacto","El puente de Alcántara sobre el río Tajo fue construido en tiempos del emperador Trajano","Las murallas de Lugo son las únicas romanas del mundo que se conservan completas","Mérida, la antigua Emerita Augusta, posee un impresionante teatro y anfiteatro romanos"]'),
('latin', 'eso', '{4}', '["Hispania fue una de las provincias más importantes del Imperio Romano","Los romanos llegaron a la Península durante la Segunda Guerra Púnica contra Cartago","La conquista completa de Hispania duró casi doscientos años de guerras","Trajano y Adriano, dos de los mejores emperadores, nacieron en la Hispania romana","La romanización transformó la lengua, las costumbres y la organización del territorio"]'),
('latin', 'eso', '{4}', '["El subjuntivo en latín se usa para expresar deseo, posibilidad o mandato","El presente de subjuntivo tiene unas desinencias diferentes a las del indicativo","Se utiliza en oraciones subordinadas que expresan finalidad, causa o condición","También aparece en oraciones independientes para expresar exhortación o deseo","El subjuntivo es uno de los modos verbales más utilizados en la subordinación latina"]'),
('latin', 'eso', '{4}', '["El calendario romano es el origen del calendario que utilizamos actualmente","Originalmente tenía diez meses y comenzaba en marzo, el mes del dios Marte","Julio César reformó el calendario añadiendo dos meses y ajustando los días del año","El mes de julio lleva su nombre y agosto el de su sucesor el emperador Augusto","Los nombres de los meses de septiembre a diciembre provienen de sus posiciones originales en latín"]');

COMMIT;
